INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 1, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You are a Global Administrator for a new Microsoft 365 tenant. You need to add the custom DNS domain contoso.com so users can sign in as ada@contoso.com. After adding the domain in the Microsoft 365 admin center, what is the next required step before the domain can be used?$ms102r$, $ms102r$[{"id":"a","text":"Wait 24 hours for automatic verification"},{"id":"b","text":"Add the TXT or MX verification record displayed by the admin center to the public DNS for contoso.com"},{"id":"c","text":"Add the domain to Microsoft Entra Connect"},{"id":"d","text":"Open a support ticket with Microsoft to confirm ownership"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Domain verification is performed by publishing the TXT (or MX) record shown in the admin center to the public DNS zone. Microsoft does not auto-verify domains over time, no support ticket is needed, and Entra Connect is unrelated to domain verification.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/setup/add-domain","label":"Microsoft Learn — Add a domain to Microsoft 365"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/get-help-with-domains/create-dns-records-at-any-dns-hosting-provider","label":"Microsoft Learn — Create DNS records at any DNS hosting provider"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You are a Global Administrator for a new Microsoft 365 tenant. You need to add the custom DNS domain contoso.com so users can sign in as ada@contoso.com. After adding the domain in the Microsoft 365 admin center, what is the next required step before the domain can be used?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Helpdesk staff must be able to reset user passwords and assign Microsoft 365 licenses but must NOT be able to manage Conditional Access policies. Which built-in Microsoft Entra role should you assign to follow least-privilege?$ms102r$, $ms102r$[{"id":"a","text":"Global Administrator"},{"id":"b","text":"User Administrator"},{"id":"c","text":"Helpdesk Administrator"},{"id":"d","text":"Authentication Administrator"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$User Administrator can create/manage users, reset passwords for most users, and assign licenses, but cannot manage Conditional Access. Helpdesk Administrator cannot assign licenses. Global Administrator is excessive. Authentication Administrator handles auth methods, not licenses.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Helpdesk staff must be able to reset user passwords and assign Microsoft 365 licenses but must NOT be able to manage Conditional Access policies. Which built-in Microsoft Entra role should you assign to follow least-privilege?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want every user who is a member of the Sales department to automatically receive a Microsoft 365 E5 license when added to the Sales group, and lose it when removed. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Direct license assignment via PowerShell"},{"id":"b","text":"Group-based licensing on a Microsoft Entra security group"},{"id":"c","text":"Conditional Access with license enforcement"},{"id":"d","text":"A retention policy targeting licenses"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Group-based licensing assigns and removes licenses automatically based on group membership. Direct assignment is per-user and manual. Conditional Access governs sign-ins, not licensing. Retention policies are unrelated to licenses.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/manage/assign-licenses-to-users","label":"Microsoft Learn — Assign licenses to users"},{"url":"https://learn.microsoft.com/en-us/entra/identity/users/licensing-groups-assign","label":"Microsoft Learn — Group-based licensing in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want every user who is a member of the Sales department to automatically receive a Microsoft 365 E5 license when added to the Sales group, and lose it when removed. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$In the Microsoft 365 admin center, where do you go to view planned changes, upcoming feature rollouts, and required actions for your tenant?$ms102r$, $ms102r$[{"id":"a","text":"Service health"},{"id":"b","text":"Message center"},{"id":"c","text":"Usage reports"},{"id":"d","text":"Adoption Score"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Message center is the source for announcements about new and changed features, planned changes, and required admin actions. Service health shows current incidents and advisories. Usage reports and Adoption Score show usage data, not change announcements.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/manage/message-center","label":"Microsoft Learn — Stay on top of changes with Message center"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/enterprise/view-service-health","label":"Microsoft Learn — How to check Microsoft 365 service health"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$In the Microsoft 365 admin center, where do you go to view planned changes, upcoming feature rollouts, and required actions for your tenant?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Intune device enrollment in a Microsoft 365 tenant.$ms102r$, $ms102r$[{"id":"a","text":"Windows Autopilot can pre-register devices and enroll them automatically when end users sign in."},{"id":"b","text":"iOS and iPadOS personal devices can be enrolled through user-driven enrollment with the Company Portal app."},{"id":"c","text":"Enrolling a device in Intune always converts it to a kiosk-only device."},{"id":"d","text":"Compliance policies evaluate device health (e.g. encryption, OS version) and can be used as a signal in Conditional Access."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$Autopilot pre-registers devices; Company Portal supports user-driven iOS/iPadOS enrollment; compliance results feed Conditional Access for device-based grant controls. Enrolling a device does not make it kiosk-only — kiosk mode is a separate configuration profile.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"},{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/device-compliance-get-started","label":"Microsoft Learn — Use device compliance policies in Intune"},{"url":"https://learn.microsoft.com/en-us/autopilot/windows-autopilot","label":"Microsoft Learn — Windows Autopilot overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Intune device enrollment in a Microsoft 365 tenant.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to require BitLocker encryption and a minimum Windows 11 build on company laptops before they can access Exchange Online and SharePoint Online. What Intune object expresses these requirements?$ms102r$, $ms102r$[{"id":"a","text":"A device configuration profile"},{"id":"b","text":"A device compliance policy"},{"id":"c","text":"An app protection policy (MAM)"},{"id":"d","text":"A Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Compliance policies define the device-health requirements (BitLocker, OS build, antivirus, etc.) used by Conditional Access to grant or block access. Configuration profiles apply settings, but compliance status is what CA evaluates. MAM protects app data on unmanaged devices; named locations are network conditions.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/device-compliance-get-started","label":"Microsoft Learn — Use device compliance policies in Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/configuration/device-profiles","label":"Microsoft Learn — Apply features and settings on devices with Intune configuration profiles"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to require BitLocker encryption and a minimum Windows 11 build on company laptops before they can access Exchange Online and SharePoint Online. What Intune object expresses these requirements?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to deploy Microsoft 365 Apps for enterprise to 5,000 Windows devices with a customized configuration (specific language packs and a defined update channel). Which tooling pair produces a reusable, declarative deployment?$ms102r$, $ms102r$[{"id":"a","text":"Click-to-Run installer downloaded from the user portal, configured per device"},{"id":"b","text":"The Office Deployment Tool (ODT) with an XML configuration file generated by the Microsoft 365 Apps admin center"},{"id":"c","text":"Microsoft 365 Apps installed only via Windows Update for Business"},{"id":"d","text":"A Group Policy Object that copies the Office 2019 MSI to clients"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$ODT with an XML configuration is the standard supported way to scale Microsoft 365 Apps deployment with defined channels, languages, and apps. Per-device portal installs do not scale. Windows Update for Business does not deploy Office. The Office 2019 MSI is a different product.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/deployoffice/deployment-guide-microsoft-365-apps","label":"Microsoft Learn — Deployment guide for Microsoft 365 Apps"},{"url":"https://learn.microsoft.com/en-us/deployoffice/admincenter/overview","label":"Microsoft Learn — Overview of the Microsoft 365 Apps admin center"},{"url":"https://learn.microsoft.com/en-us/deployoffice/deploy-microsoft-365-apps-office-deployment-tool","label":"Microsoft Learn — Install Microsoft 365 Apps with the Office Deployment Tool"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to deploy Microsoft 365 Apps for enterprise to 5,000 Windows devices with a customized configuration (specific language packs and a defined update channel). Which tooling pair produces a reusable, declarative deployment?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which update channel for Microsoft 365 Apps for enterprise receives new productivity features once a month on a predictable schedule and is the default for enterprise users?$ms102r$, $ms102r$[{"id":"a","text":"Current Channel"},{"id":"b","text":"Monthly Enterprise Channel"},{"id":"c","text":"Semi-Annual Enterprise Channel"},{"id":"d","text":"Beta Channel"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Monthly Enterprise Channel delivers new features once a month on a predictable second-Tuesday cadence and is recommended for most enterprises. Current Channel updates continuously. Semi-Annual delivers features every 6 months. Beta is for early adopters/IT pros.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/deployoffice/overview-update-channels","label":"Microsoft Learn — Overview of update channels for Microsoft 365 Apps"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which update channel for Microsoft 365 Apps for enterprise receives new productivity features once a month on a predictable schedule and is the default for enterprise users?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to delegate temporary administrative access to a partner so they can manage your Microsoft 365 tenant while keeping the relationship governed by least-privilege and time-bound roles. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Add the partner as a Global Administrator in your tenant"},{"id":"b","text":"Granular Delegated Admin Privileges (GDAP) with specific Entra roles and an expiration"},{"id":"c","text":"Share the Global Admin password through a secure vault"},{"id":"d","text":"Add the partner as a guest user with no roles"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$GDAP gives partners only the Entra roles they need, scoped and time-bounded. Sharing credentials or granting standing Global Admin breaks least-privilege. A guest with no roles cannot administer the tenant.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/partner-center/customers/gdap-introduction","label":"Microsoft Learn — Delegated administration and GDAP"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to delegate temporary administrative access to a partner so they can manage your Microsoft 365 tenant while keeping the relationship governed by least-privilege and time-bound roles. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Managed Service Provider needs a single pane of glass to manage 80 small-business Microsoft 365 tenants — viewing health, security baseline status, and applying actions across them. Which service is purpose-built for this?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft 365 Lighthouse"},{"id":"b","text":"Microsoft 365 admin center per tenant"},{"id":"c","text":"Microsoft Entra Connect Health"},{"id":"d","text":"Microsoft Purview portal"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft 365 Lighthouse is the multi-tenant management portal for partners managing small/medium business tenants. The per-tenant admin center scales poorly. Entra Connect Health monitors hybrid identity, not multi-tenant operations. Purview is for data governance.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/lighthouse/m365-lighthouse-overview","label":"Microsoft Learn — Multi-tenant management with Microsoft 365 Lighthouse"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Managed Service Provider needs a single pane of glass to manage 80 small-business Microsoft 365 tenants — viewing health, security baseline status, and applying actions across them. Which service is purpose-built for this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which approach should an organization use to grant a Global Administrator role to a user only for the four hours needed to perform a configuration change, rather than as a standing assignment?$ms102r$, $ms102r$[{"id":"a","text":"Use Microsoft Entra Privileged Identity Management (PIM) to assign the role as eligible and require activation with justification"},{"id":"b","text":"Assign the user as a permanent Global Administrator and remove the role afterwards"},{"id":"c","text":"Share the existing break-glass Global Admin account credentials for the duration"},{"id":"d","text":"Use a Conditional Access policy to grant the role temporarily"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PIM provides just-in-time, time-bound, approval-gated activation of privileged roles with audit. Permanent assignment with later removal is error-prone. Sharing break-glass credentials defeats their purpose. Conditional Access does not grant roles — it controls access to apps.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which approach should an organization use to grant a Global Administrator role to a user only for the four hours needed to perform a configuration change, rather than as a standing assignment?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to know whether Exchange Online is currently experiencing a service incident affecting users in your tenant. Which page in the Microsoft 365 admin center should you open?$ms102r$, $ms102r$[{"id":"a","text":"Service health"},{"id":"b","text":"Message center"},{"id":"c","text":"Reports > Usage"},{"id":"d","text":"Adoption Score"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Service health shows the live status of Microsoft 365 services for your tenant, including incidents and advisories. Message center announces future changes. Usage reports and Adoption Score show usage patterns, not live service status.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/enterprise/view-service-health","label":"Microsoft Learn — How to check Microsoft 365 service health"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to know whether Exchange Online is currently experiencing a service incident affecting users in your tenant. Which page in the Microsoft 365 admin center should you open?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You assigned the Exchange Administrator role to a user, but they cannot manage mailboxes for users in the Finance organizational unit while still managing the rest. Which feature lets you restrict an admin role to a subset of objects?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy filtered by group"},{"id":"b","text":"Microsoft Entra administrative units scoped to the Finance OU"},{"id":"c","text":"A separate Exchange role group with Finance permissions only"},{"id":"d","text":"Dynamic membership rules on the Exchange Administrator role"}]$ms102r$::jsonb, $ms102r$["c"]$ms102r$::jsonb, $ms102r$For Exchange-specific scoping (mailboxes/recipients), you create an Exchange Online role group with the appropriate write/admin role and a write scope to the Finance group/OU. Administrative units scope Entra-managed identities. CA controls user sign-ins. Roles do not have dynamic membership.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/administrative-units","label":"Microsoft Learn — Administrative units in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You assigned the Exchange Administrator role to a user, but they cannot manage mailboxes for users in the Finance organizational unit while still managing the rest. Which feature lets you restrict an admin role to a subset of objects?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which report in the Microsoft 365 admin center can show executives the active usage of Teams, Exchange, SharePoint, and OneDrive across the tenant for the last 30/90/180 days?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft 365 usage analytics / activity reports"},{"id":"b","text":"Service health dashboard"},{"id":"c","text":"Audit log search in Microsoft Purview"},{"id":"d","text":"Conditional Access insights and reporting"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The activity reports / Microsoft 365 usage analytics surface active-user counts and per-workload usage trends. Service health reports incidents. Purview audit search returns admin/user actions. CA insights report policy outcomes.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/usage-analytics/usage-analytics","label":"Microsoft Learn — Microsoft 365 usage analytics"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/activity-reports/activity-reports","label":"Microsoft Learn — Activity reports in the Microsoft 365 admin center"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which report in the Microsoft 365 admin center can show executives the active usage of Teams, Exchange, SharePoint, and OneDrive across the tenant for the last 30/90/180 days?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your tenant currently has no devices in Intune. You want to allow employees to enroll their corporate Windows devices automatically when they sign in with their work account. What must be configured?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy that requires compliant devices"},{"id":"b","text":"Microsoft Entra ID > Mobility (MDM and MAM) so Intune is set as the MDM authority and auto-enrollment is enabled for users"},{"id":"c","text":"A retention policy that targets devices"},{"id":"d","text":"Group-based licensing for Intune only"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Auto-enrollment for Entra-joined Windows devices is set under Entra ID > Mobility (MDM and MAM) by configuring the MDM user scope and ensuring users are licensed for Intune. CA requires devices first to be enrolled; retention policies are for content; licensing alone is necessary but not sufficient.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your tenant currently has no devices in Intune. You want to allow employees to enroll their corporate Windows devices automatically when they sign in with their work account. What must be configured?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$During tenant setup, where do you choose the geography where your Microsoft 365 customer data will be stored at rest?$ms102r$, $ms102r$[{"id":"a","text":"The data residency is selected at sign-up based on the country/region of the tenant — it cannot be changed afterwards without a tenant move request"},{"id":"b","text":"It can be changed in Microsoft Entra Connect at any time"},{"id":"c","text":"It is set per-user in the Microsoft 365 admin center"},{"id":"d","text":"It is automatically replicated to every Azure region"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Data residency for Microsoft 365 services is determined by the country/region you select when the tenant is created. Moving data to another geography requires a Microsoft-managed tenant move. Entra Connect is unrelated. Data is not automatically replicated to every region.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/enterprise/o365-data-locations","label":"Microsoft Learn — Where is your Microsoft 365 data located?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$During tenant setup, where do you choose the geography where your Microsoft 365 customer data will be stored at rest?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Windows Autopilot.$ms102r$, $ms102r$[{"id":"a","text":"Autopilot can use a hardware hash to pre-register devices to your tenant before they are shipped to users."},{"id":"b","text":"Autopilot user-driven mode enrolls the device in Microsoft Entra and Intune during first sign-in."},{"id":"c","text":"Autopilot replaces Microsoft Intune as the MDM authority."},{"id":"d","text":"Autopilot profiles can enforce skipping the EULA, OOBE privacy prompts, and the local account creation step."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$Autopilot pre-registers devices via hardware hash, enrolls them in Entra+Intune during OOBE, and can skip OOBE prompts via the deployment profile. Intune remains the MDM authority — Autopilot is a provisioning service, not a replacement.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/autopilot/windows-autopilot","label":"Microsoft Learn — Windows Autopilot overview"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Windows Autopilot.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which approach BEST allows a small company to start using their existing contoso.com domain for Microsoft 365 email while keeping the onmicrosoft.com tenant name for backend identifiers?$ms102r$, $ms102r$[{"id":"a","text":"Rename the tenant to contoso.com"},{"id":"b","text":"Add contoso.com as a verified domain and set it as the default for new mailboxes"},{"id":"c","text":"Use only the onmicrosoft.com domain for email"},{"id":"d","text":"Federate the on-premises Active Directory with contoso.com"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$You add and verify contoso.com as a custom domain and set it as default; the tenant onmicrosoft.com identifier remains. Tenants cannot be renamed at will. Using only onmicrosoft.com defeats the goal. Federation is unrelated to adding a domain.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/setup/add-domain","label":"Microsoft Learn — Add a domain to Microsoft 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which approach BEST allows a small company to start using their existing contoso.com domain for Microsoft 365 email while keeping the onmicrosoft.com tenant name for backend identifiers?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 1, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to create a new cloud-only user named Lin Wei who will sign in as lin@contoso.com and be assigned an E5 license. Where in the Microsoft Entra admin center do you start?$ms102r$, $ms102r$[{"id":"a","text":"Identity > Users > New user > Create new user"},{"id":"b","text":"Identity > Roles & admins > Role assignments"},{"id":"c","text":"Identity Governance > Entitlement management"},{"id":"d","text":"Identity > External Identities > B2B invitation"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Cloud-only users are created from Identity > Users > New user > Create new user. Roles & admins assigns roles to existing principals. Entitlement management assigns access packages, not creates users. B2B is for inviting external guests.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-create-delete-users","label":"Microsoft Learn — How to add or delete users in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to create a new cloud-only user named Lin Wei who will sign in as lin@contoso.com and be assigned an E5 license. Where in the Microsoft Entra admin center do you start?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A multinational deploys Microsoft Entra Connect with password hash synchronization (PHS). The on-premises AD password policy must continue to be the authority. What happens when a user changes their password in on-premises AD?$ms102r$, $ms102r$[{"id":"a","text":"The change is rejected unless the user also resets it in Entra ID"},{"id":"b","text":"A hash of the new password hash is synced to Entra ID within minutes; cloud sign-ins continue to work"},{"id":"c","text":"The user must reset MFA"},{"id":"d","text":"Entra Connect federates the password to ADFS"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$PHS syncs a hash-of-the-hash from on-premises AD to Entra ID approximately every 2 minutes, so cloud sign-ins use the same password. PHS is independent of ADFS and does not invalidate MFA registrations.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-azure-ad-connect","label":"Microsoft Learn — What is Microsoft Entra Connect?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-password-hash-synchronization","label":"Microsoft Learn — Implement password hash synchronization with Microsoft Entra Connect Sync"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A multinational deploys Microsoft Entra Connect with password hash synchronization (PHS). The on-premises AD password policy must continue to be the authority. What happens when a user changes their password in on-premises AD?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want sign-in attempts from anonymous IP addresses (Tor) to be blocked, and sign-ins from medium-or-high risk users to require a password change. Which Microsoft Entra capability provides both?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra ID Protection sign-in risk and user risk policies"},{"id":"b","text":"Privileged Identity Management"},{"id":"c","text":"Microsoft Entra Connect filtering"},{"id":"d","text":"Microsoft Defender for Cloud Apps file policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ID Protection ships sign-in-risk and user-risk policies that can require MFA, block, or force a password change. PIM governs role activation. Entra Connect filtering controls object sync. Defender for Cloud Apps governs SaaS, not sign-in risk.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want sign-in attempts from anonymous IP addresses (Tor) to be blocked, and sign-ins from medium-or-high risk users to require a password change. Which Microsoft Entra capability provides both?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to require multifactor authentication for all users when accessing the Microsoft 365 portal, except when the sign-in originates from your corporate office IP range. What should you configure?$ms102r$, $ms102r$[{"id":"a","text":"Per-user MFA enabled for every account"},{"id":"b","text":"A Conditional Access policy that grants access only with MFA, with the corporate IP range added as a trusted named location and excluded from the policy"},{"id":"c","text":"Security defaults"},{"id":"d","text":"Microsoft Entra Connect filtering rules"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Conditional Access lets you target users/apps and exclude trusted named locations from the MFA requirement. Per-user MFA prompts everywhere and cannot exclude networks. Security defaults are tenant-wide with no granular exclusions. Entra Connect is for directory sync.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-conditional-access-policies","label":"Microsoft Learn — Build a Conditional Access policy"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/location-condition","label":"Microsoft Learn — Named locations in Conditional Access"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to require multifactor authentication for all users when accessing the Microsoft 365 portal, except when the sign-in originates from your corporate office IP range. What should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Conditional Access policy evaluation in Microsoft Entra ID.$ms102r$, $ms102r$[{"id":"a","text":"Conditional Access policies are evaluated AFTER successful first-factor authentication."},{"id":"b","text":"Multiple matching policies are combined; if any policy results in Block, the sign-in is blocked."},{"id":"c","text":"If multiple policies require different grant controls (e.g. MFA and compliant device), all controls must be satisfied."},{"id":"d","text":"Conditional Access can change a user's assigned license."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$CA is post-authentication; results combine across policies; Block trumps; grant controls are ANDed across matching policies. Conditional Access cannot assign or change licenses — that is a separate provisioning concern.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-conditional-access-policies","label":"Microsoft Learn — Build a Conditional Access policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Conditional Access policy evaluation in Microsoft Entra ID.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to roll out passwordless sign-in for executives using FIDO2 security keys. Where do you enable FIDO2 as an allowed authentication method?$ms102r$, $ms102r$[{"id":"a","text":"Identity > Authentication methods > Policies > FIDO2 security key"},{"id":"b","text":"Identity > Conditional Access > Authentication strengths"},{"id":"c","text":"Identity Governance > Access reviews"},{"id":"d","text":"Security > Multifactor authentication > Account lockout"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$FIDO2 is enabled and scoped under Identity > Authentication methods > Policies. Authentication strengths reference allowed methods but do not enable them. Access reviews are governance. MFA account lockout is a legacy per-user MFA setting.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-passwordless","label":"Microsoft Learn — Passwordless authentication options for Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to roll out passwordless sign-in for executives using FIDO2 security keys. Where do you enable FIDO2 as an allowed authentication method?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A partner company asks for limited access to a SharePoint site in your tenant. You should not create full accounts for each partner user. Which approach is correct?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra B2B guest invitations"},{"id":"b","text":"Pass-through authentication"},{"id":"c","text":"Microsoft Entra Domain Services"},{"id":"d","text":"Service principal credentials"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$B2B collaboration lets you invite external users as guests who sign in with their own identity and receive permissions to resources in your tenant. PTA is for on-prem password validation. Entra Domain Services is a managed domain. Service principals are app identities.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A partner company asks for limited access to a SharePoint site in your tenant. You should not create full accounts for each partner user. Which approach is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want managers to certify quarterly that their direct reports still need access to a sensitive Microsoft 365 group. If a manager does not respond, access should be removed automatically. What should you configure?$ms102r$, $ms102r$[{"id":"a","text":"A Microsoft Entra access review that targets the group, reviewer = manager, and \"If reviewers don't respond\" = remove access"},{"id":"b","text":"A Conditional Access policy that blocks the group"},{"id":"c","text":"An Intune compliance policy"},{"id":"d","text":"A Purview retention policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Access reviews recurrently certify membership/access. You can set the manager as the reviewer and configure auto-remove when reviewers don't respond. CA, Intune compliance, and retention policies don't certify group membership.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/access-reviews-overview","label":"Microsoft Learn — What are access reviews?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want managers to certify quarterly that their direct reports still need access to a sensitive Microsoft 365 group. If a manager does not respond, access should be removed automatically. What should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports they were prompted to reset their password by a Microsoft Entra "Sign-in risk" policy after traveling to a new country. The IT team wants to understand why. Which signals does Entra ID Protection use to compute sign-in risk?$ms102r$, $ms102r$[{"id":"a","text":"Anonymous IP, atypical travel, malware-linked IP, unfamiliar sign-in properties, leaked credentials"},{"id":"b","text":"Disk encryption status of the device"},{"id":"c","text":"How many Microsoft 365 licenses the user holds"},{"id":"d","text":"The user's tenure (years since hire)"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ID Protection computes sign-in risk from signals such as anonymous IP, atypical travel, malware-linked IP, unfamiliar sign-in properties, password spray, and leaked credentials. Device encryption, licenses, and tenure are not sign-in-risk signals.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports they were prompted to reset their password by a Microsoft Entra "Sign-in risk" policy after traveling to a new country. The IT team wants to understand why. Which signals does Entra ID Protection use to compute sign-in risk?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which feature lets end users register and reset their own passwords (subject to administrator-defined authentication methods) without contacting the helpdesk?$ms102r$, $ms102r$[{"id":"a","text":"Self-service password reset (SSPR)"},{"id":"b","text":"Privileged Identity Management"},{"id":"c","text":"Microsoft Entra Connect"},{"id":"d","text":"Per-user MFA"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$SSPR lets users reset their own passwords with registered methods (mobile phone, authenticator, email, security questions). PIM is for privileged role activation. Entra Connect syncs directories. Per-user MFA prompts for MFA but does not reset passwords.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-sspr-howitworks","label":"Microsoft Learn — How it works: Microsoft Entra self-service password reset"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which feature lets end users register and reset their own passwords (subject to administrator-defined authentication methods) without contacting the helpdesk?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need a security group whose membership is automatically calculated from the user attribute "department". Which group setting is required?$ms102r$, $ms102r$[{"id":"a","text":"Assigned membership"},{"id":"b","text":"Dynamic user membership with a rule like (user.department -eq \"Sales\")"},{"id":"c","text":"Mail-enabled distribution list"},{"id":"d","text":"Microsoft 365 group with a department label"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Dynamic membership evaluates a rule against user properties to add/remove members automatically. Assigned membership is static. Distribution lists and labels do not auto-evaluate department for security access.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-manage-groups","label":"Microsoft Learn — Manage groups in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/users/groups-dynamic-membership","label":"Microsoft Learn — Dynamic membership rules for groups"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need a security group whose membership is automatically calculated from the user attribute "department". Which group setting is required?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$In a hybrid environment, you want users to sign in to Microsoft 365 with their on-premises AD passwords AND for the password validation to occur against on-premises AD in real time, without password hashes in the cloud. Which option meets the requirement?$ms102r$, $ms102r$[{"id":"a","text":"Password hash synchronization"},{"id":"b","text":"Pass-through authentication (PTA) with seamless SSO"},{"id":"c","text":"Cloud-only identities with self-service password reset"},{"id":"d","text":"Microsoft Entra Cloud Sync"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$PTA validates each sign-in against on-premises AD via a lightweight agent, without storing password hashes in the cloud. PHS stores hashes in the cloud. Cloud-only identities have no on-prem connection. Cloud Sync is a sync engine choice — it still typically uses PHS.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-pta","label":"Microsoft Learn — Microsoft Entra pass-through authentication"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sso","label":"Microsoft Learn — Microsoft Entra seamless single sign-on"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$In a hybrid environment, you want users to sign in to Microsoft 365 with their on-premises AD passwords AND for the password validation to occur against on-premises AD in real time, without password hashes in the cloud. Which option meets the requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You assigned the User Administrator role at the tenant scope to a delegated admin, but you want a different admin to manage only the users in the "Lagos" administrative unit. Which assignment shape achieves the second requirement?$ms102r$, $ms102r$[{"id":"a","text":"Assign the User Administrator role with the Lagos administrative unit as the role-assignment scope"},{"id":"b","text":"Add the admin as a Global Administrator and ask them to operate only on Lagos users"},{"id":"c","text":"Use a dynamic group of Lagos users as the target of a Conditional Access policy"},{"id":"d","text":"Configure SSPR for the Lagos administrative unit only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Administrative-unit-scoped role assignments restrict the admin to the objects in that AU. Global Administrator is unscoped. CA gates access; SSPR is for password reset — neither delegates user management.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/administrative-units","label":"Microsoft Learn — Administrative units in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You assigned the User Administrator role at the tenant scope to a delegated admin, but you want a different admin to manage only the users in the "Lagos" administrative unit. Which assignment shape achieves the second requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want all guest accounts that have been inactive in your tenant for 90 days to be automatically reviewed and removed if no longer needed. Which Microsoft Entra Identity Governance capability provides this?$ms102r$, $ms102r$[{"id":"a","text":"A recurring access review targeting guest users with auto-apply results to remove inactive guests"},{"id":"b","text":"Per-user MFA"},{"id":"c","text":"A retention policy on the guest mailbox"},{"id":"d","text":"Group-based licensing for guests"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Access reviews can target guests, include inactivity/recommendations, and auto-apply removal. MFA does not remove guests. Retention is for content. Licensing does not govern guest lifecycle.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/access-reviews-overview","label":"Microsoft Learn — What are access reviews?"},{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want all guest accounts that have been inactive in your tenant for 90 days to be automatically reviewed and removed if no longer needed. Which Microsoft Entra Identity Governance capability provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports they never see an MFA prompt when signing in to Microsoft 365 from the corporate office, but they are required to use MFA from home. Which Microsoft Entra construct most likely produced this experience?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy that requires MFA, with the corporate office IP range configured as a trusted named location excluded from the policy"},{"id":"b","text":"A Microsoft Entra Connect filtering rule"},{"id":"c","text":"A retention policy on the user"},{"id":"d","text":"A Defender for Endpoint device tag"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CA policies can exclude trusted named locations (corporate IP ranges) so users in those networks bypass MFA. Connect filtering controls sync; retention is content; MDE tags are device metadata.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/location-condition","label":"Microsoft Learn — Named locations in Conditional Access"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports they never see an MFA prompt when signing in to Microsoft 365 from the corporate office, but they are required to use MFA from home. Which Microsoft Entra construct most likely produced this experience?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your CTO wants every Microsoft Entra ID privileged role assignment to require a justification, expire in 8 hours, and trigger an email to the security team on every activation. Which Privileged Identity Management settings are required?$ms102r$, $ms102r$[{"id":"a","text":"Configure the role assignment as eligible and tune the role settings to require justification, set maximum activation duration to 8 hours, and add the security team as notification recipients"},{"id":"b","text":"Make the user a permanent role member with MFA only"},{"id":"c","text":"Block sign-ins for the user via Conditional Access"},{"id":"d","text":"Remove the role and re-grant it manually each day"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PIM role settings expose activation maximum duration, required justification, MFA, approval, and email notifications. Permanent assignments bypass JIT controls. CA blocks do not enable activations. Manual cycling is error-prone.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your CTO wants every Microsoft Entra ID privileged role assignment to require a justification, expire in 8 hours, and trigger an email to the security team on every activation. Which Privileged Identity Management settings are required?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to enforce that all sign-ins to Microsoft 365 require a token strength that includes a phishing-resistant factor (e.g. FIDO2 or Windows Hello for Business) for users with the Global Administrator role. Which combination should you configure?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy targeting the Global Administrators directory role, with the Authentication strength grant control set to Phishing-resistant MFA"},{"id":"b","text":"Per-user MFA for the same admins"},{"id":"c","text":"A retention label on the admins' mailboxes"},{"id":"d","text":"A Microsoft Entra ID Protection sign-in risk policy with low threshold"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CA supports targeting directory roles, and Authentication strengths can require phishing-resistant MFA. Per-user MFA cannot enforce method type. Retention labels and risk policies do not select methods.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-passwordless","label":"Microsoft Learn — Passwordless authentication options for Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to enforce that all sign-ins to Microsoft 365 require a token strength that includes a phishing-resistant factor (e.g. FIDO2 or Windows Hello for Business) for users with the Global Administrator role. Which combination should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user signs in successfully and starts a long Microsoft 365 session. Twenty minutes later, the security team confirms the account is compromised and disables it in Microsoft Entra. With which feature enabled will the active session be revoked near-real-time, instead of waiting up to an hour for token expiry?$ms102r$, $ms102r$[{"id":"a","text":"Continuous access evaluation (CAE) for the cloud apps that support it"},{"id":"b","text":"Conditional Access sign-in frequency = 1 hour"},{"id":"c","text":"Pass-through authentication"},{"id":"d","text":"Self-service password reset"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CAE allows Entra ID and supporting services to revoke active tokens in near-real-time when critical events (disable, password reset, location change) occur. Sign-in frequency only forces a re-prompt at the next interval; PTA is auth flow; SSPR is password reset.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user signs in successfully and starts a long Microsoft 365 session. Twenty minutes later, the security team confirms the account is compromised and disables it in Microsoft Entra. With which feature enabled will the active session be revoked near-real-time, instead of waiting up to an hour for token expiry?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 1, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Where do security operations analysts triage incidents and alerts across Defender for Endpoint, Defender for Office 365, Defender for Identity, and Defender for Cloud Apps in a single view?$ms102r$, $ms102r$[{"id":"a","text":"The Microsoft Defender portal (security.microsoft.com)"},{"id":"b","text":"The Microsoft Entra admin center"},{"id":"c","text":"The Microsoft Purview portal"},{"id":"d","text":"The Microsoft 365 admin center"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The Microsoft Defender portal is the unified XDR experience for incidents, alerts, hunting, and configuration across all Defender workloads. Entra, Purview, and the M365 admin center surface different concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender-portal","label":"Microsoft Learn — The Microsoft Defender portal"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender","label":"Microsoft Learn — Microsoft Defender XDR overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Where do security operations analysts triage incidents and alerts across Defender for Endpoint, Defender for Office 365, Defender for Identity, and Defender for Cloud Apps in a single view?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Defender XDR incident shows seven correlated alerts that span an email click, a malicious file download, and a credential-theft attempt on an endpoint. What is the primary benefit of the incident view over the alert view?$ms102r$, $ms102r$[{"id":"a","text":"It always closes the alerts automatically"},{"id":"b","text":"It correlates alerts across workloads (email/endpoint/identity/cloud apps) into a single multi-stage attack story"},{"id":"c","text":"It blocks all senders on the message permanently"},{"id":"d","text":"It applies a retention label to mailboxes"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Incidents correlate related alerts across products into one attack story so SOCs can investigate end-to-end. They do not auto-close alerts (AIR can resolve some), block senders, or apply retention labels.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender","label":"Microsoft Learn — Microsoft Defender XDR overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Defender XDR incident shows seven correlated alerts that span an email click, a malicious file download, and a credential-theft attempt on an endpoint. What is the primary benefit of the incident view over the alert view?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to write a custom query that searches for sign-ins from new countries followed within an hour by mailbox-rule creation. Which Defender XDR capability lets you author such cross-product queries in Kusto Query Language?$ms102r$, $ms102r$[{"id":"a","text":"Advanced hunting"},{"id":"b","text":"Secure Score"},{"id":"c","text":"Quarantine"},{"id":"d","text":"Safe Attachments"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Advanced hunting exposes tables (IdentityLogonEvents, EmailEvents, DeviceEvents, CloudAppEvents) queried with KQL to author custom detections. Secure Score is posture. Quarantine and Safe Attachments are MDO controls.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/advanced-hunting-overview","label":"Microsoft Learn — Advanced hunting in Microsoft Defender XDR"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to write a custom query that searches for sign-ins from new countries followed within an hour by mailbox-rule creation. Which Defender XDR capability lets you author such cross-product queries in Kusto Query Language?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL valid methods to onboard a Windows 11 device to Microsoft Defender for Endpoint.$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Intune (MDM) configuration profile"},{"id":"b","text":"Local script (run interactively) from the Defender portal"},{"id":"c","text":"Group Policy with the onboarding package"},{"id":"d","text":"Sending an MX record to the device"}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$Intune, local onboarding script, Group Policy, and Microsoft Configuration Manager are all supported onboarding methods. MX records are DNS records for mail routing, not endpoint onboarding.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/onboard-configure","label":"Microsoft Learn — Onboard devices to Microsoft Defender for Endpoint"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL valid methods to onboard a Windows 11 device to Microsoft Defender for Endpoint.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to block Office applications from creating executable child processes — a known macro-malware pattern — without breaking legitimate macro use cases. Which Defender for Endpoint feature should you configure?$ms102r$, $ms102r$[{"id":"a","text":"Attack surface reduction (ASR) rules in audit-then-block mode"},{"id":"b","text":"Microsoft Defender Antivirus quick scan"},{"id":"c","text":"Defender Vulnerability Management baseline assessment"},{"id":"d","text":"EDR in block mode"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ASR rules harden against specific attack patterns (e.g. "Block Office applications from creating child processes"). Best practice is audit first, then block. AV scans, vulnerability baselines, and EDR-in-block are different controls.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/attack-surface-reduction","label":"Microsoft Learn — Attack surface reduction rules overview"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to block Office applications from creating executable child processes — a known macro-malware pattern — without breaking legitimate macro use cases. Which Defender for Endpoint feature should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A vulnerability scan in Defender Vulnerability Management identifies a high-severity CVE on 1,200 Windows endpoints. Which built-in capability lets you push a remediation request directly to the Intune admin?$ms102r$, $ms102r$[{"id":"a","text":"Recommendations > Request remediation in the Defender portal, which creates a remediation task in Intune"},{"id":"b","text":"A manual email to the helpdesk"},{"id":"c","text":"A Conditional Access policy blocking the endpoints"},{"id":"d","text":"A retention policy targeting the CVE number"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$In Defender Vulnerability Management, recommendations include a "Request remediation" action that integrates with Intune, creating a remediation task assignable to IT admins. Email, CA, and retention policies are not part of this workflow.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-vulnerability-management/defender-vulnerability-management","label":"Microsoft Learn — Microsoft Defender Vulnerability Management"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A vulnerability scan in Defender Vulnerability Management identifies a high-severity CVE on 1,200 Windows endpoints. Which built-in capability lets you push a remediation request directly to the Intune admin?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user clicks a phishing link. Defender XDR's automated investigation determines the email was malicious and the device shows no signs of compromise. Which capability automatically remediated the user's mailbox and other tenant mailboxes?$ms102r$, $ms102r$[{"id":"a","text":"Zero-hour Auto Purge (ZAP) in Defender for Office 365"},{"id":"b","text":"Safe Links time-of-click protection"},{"id":"c","text":"Defender for Endpoint EDR in block mode"},{"id":"d","text":"Microsoft Purview retention policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ZAP retroactively purges malicious messages from mailboxes after delivery as new signal is gathered. Safe Links protects URLs at click-time but does not purge messages. EDR is endpoint. Retention does not remove malicious mail.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-links-about","label":"Microsoft Learn — Safe Links in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user clicks a phishing link. Defender XDR's automated investigation determines the email was malicious and the device shows no signs of compromise. Which capability automatically remediated the user's mailbox and other tenant mailboxes?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to enforce Microsoft's recommended baseline of anti-phish, anti-spam, anti-malware, Safe Attachments, and Safe Links for all users with minimal configuration. Which Defender for Office 365 feature should you apply?$ms102r$, $ms102r$[{"id":"a","text":"Preset security policies (Standard or Strict)"},{"id":"b","text":"A single custom anti-malware policy"},{"id":"c","text":"A transport rule that allows everything"},{"id":"d","text":"A retention policy for inbox"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Preset security policies (Standard/Strict) apply Microsoft-recommended values across the entire EOP+MDO stack. A single anti-malware policy covers only one workload. Transport rules don't configure preset security. Retention is unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/preset-security-policies","label":"Microsoft Learn — Preset security policies in EOP and Microsoft Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/eop-about","label":"Microsoft Learn — Exchange Online Protection overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to enforce Microsoft's recommended baseline of anti-phish, anti-spam, anti-malware, Safe Attachments, and Safe Links for all users with minimal configuration. Which Defender for Office 365 feature should you apply?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports they never received an expected purchase order from a partner. You need to find out whether the message was quarantined, and release it if appropriate. Where should you start?$ms102r$, $ms102r$[{"id":"a","text":"The quarantine page in the Microsoft Defender portal"},{"id":"b","text":"Search-Mailbox in Exchange PowerShell"},{"id":"c","text":"The Microsoft 365 admin center > Users"},{"id":"d","text":"Purview eDiscovery (Standard)"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The Defender portal's quarantine page lists messages held by anti-spam/anti-phish/malware/ZAP and allows release. Search-Mailbox is deprecated. Users blade lists accounts only. eDiscovery is for legal hold, not quarantine release.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/quarantine-about","label":"Microsoft Learn — Quarantined email messages in EOP and Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender-portal","label":"Microsoft Learn — The Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports they never received an expected purchase order from a partner. You need to find out whether the message was quarantined, and release it if appropriate. Where should you start?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to simulate a credential-harvest phishing campaign against employees and require those who click through to complete training. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Attack simulation training in Microsoft Defender for Office 365"},{"id":"b","text":"Microsoft Purview communication compliance"},{"id":"c","text":"Microsoft Entra ID Protection sign-in risk"},{"id":"d","text":"Defender for Cloud Apps shadow IT discovery"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Attack simulation training runs simulated phishing campaigns and assigns training to users who interact. Communication compliance reviews internal messages. ID Protection detects risky sign-ins. Defender for Cloud Apps surfaces shadow SaaS.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/attack-simulation-training-get-started","label":"Microsoft Learn — Get started using Attack simulation training"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to simulate a credential-harvest phishing campaign against employees and require those who click through to complete training. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your domain receives spoofed messages claiming to be from contoso.com. Which DNS records, configured in your authoritative DNS, allow recipient servers to authenticate that mail truly originated from your authorized senders?$ms102r$, $ms102r$[{"id":"a","text":"SPF, DKIM, and DMARC"},{"id":"b","text":"A and AAAA records only"},{"id":"c","text":"MX and CNAME only"},{"id":"d","text":"TXT records for site verification only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$SPF authorizes sending IPs, DKIM cryptographically signs messages, and DMARC publishes a policy that ties the two to the visible From: address. A/AAAA, MX, and verification TXTs do not authenticate mail authorship.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-spf-configure","label":"Microsoft Learn — Set up SPF to help prevent spoofing"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dkim-configure","label":"Microsoft Learn — Use DKIM to validate outbound email sent from your custom domain"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dmarc-configure","label":"Microsoft Learn — Use DMARC to validate email"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your domain receives spoofed messages claiming to be from contoso.com. Which DNS records, configured in your authoritative DNS, allow recipient servers to authenticate that mail truly originated from your authorized senders?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A finance employee receives a message claiming to be from the CEO requesting an urgent wire transfer. Which Microsoft Defender for Office 365 feature specifically protects against this kind of impersonation?$ms102r$, $ms102r$[{"id":"a","text":"Anti-phishing policy impersonation protection (with the CEO listed as a protected user)"},{"id":"b","text":"Safe Attachments dynamic delivery"},{"id":"c","text":"Microsoft 365 Apps update channels"},{"id":"d","text":"Exchange Online archiving"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Anti-phishing policies in Defender for Office 365 include impersonation protection for protected users and domains. Safe Attachments scans files. Update channels and archiving are unrelated to BEC prevention.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/anti-phishing-policies-about","label":"Microsoft Learn — Anti-phishing policies in Microsoft 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A finance employee receives a message claiming to be from the CEO requesting an urgent wire transfer. Which Microsoft Defender for Office 365 feature specifically protects against this kind of impersonation?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to detect lateral movement, Pass-the-Hash, and Golden Ticket attacks against on-premises Active Directory and feed the alerts into Defender XDR. Which product should you deploy?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Defender for Identity (sensor on domain controllers)"},{"id":"b","text":"Microsoft Defender for Endpoint on the domain controllers only"},{"id":"c","text":"Microsoft Defender for Cloud Apps"},{"id":"d","text":"Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Defender for Identity uses sensors on domain controllers (and AD FS / Entra Connect when applicable) to detect on-prem identity attacks and forwards alerts to the XDR portal. The other Defender products do not analyze AD authentication traffic.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-for-identity/what-is","label":"Microsoft Learn — What is Microsoft Defender for Identity?"},{"url":"https://learn.microsoft.com/en-us/defender-for-identity/deploy/capacity-planning","label":"Microsoft Learn — Plan capacity for Microsoft Defender for Identity"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to detect lateral movement, Pass-the-Hash, and Golden Ticket attacks against on-premises Active Directory and feed the alerts into Defender XDR. Which product should you deploy?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to discover what unsanctioned SaaS apps employees use, by uploading firewall logs to Microsoft Defender for Cloud Apps. Which feature analyzes these logs?$ms102r$, $ms102r$[{"id":"a","text":"Cloud Discovery"},{"id":"b","text":"Conditional Access App Control"},{"id":"c","text":"File policies"},{"id":"d","text":"OAuth app governance"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Cloud Discovery analyses traffic logs (from firewalls/proxies or Defender for Endpoint) to surface shadow IT and risk scores. App Control session-controls sanctioned apps. File policies govern files in sanctioned apps. OAuth app governance reviews consented apps.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/set-up-cloud-discovery","label":"Microsoft Learn — Set up Cloud Discovery in Microsoft Defender for Cloud Apps"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to discover what unsanctioned SaaS apps employees use, by uploading firewall logs to Microsoft Defender for Cloud Apps. Which feature analyzes these logs?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Defender for Cloud Apps file policies.$ms102r$, $ms102r$[{"id":"a","text":"They can detect external sharing of files containing sensitive information types in OneDrive/SharePoint."},{"id":"b","text":"They can quarantine, change sharing, or apply a sensitivity label as governance actions."},{"id":"c","text":"They run only on Windows endpoints."},{"id":"d","text":"They reuse Microsoft Purview sensitive information types."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$File policies inspect content in connected SaaS apps (M365, Box, etc.), reuse Purview SITs, and can quarantine, change sharing, or apply labels. They are SaaS-side controls — not limited to Windows endpoints.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/control-cloud-apps-with-policies","label":"Microsoft Learn — Control cloud apps with policies"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Defender for Cloud Apps file policies.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft 365 capability gives a single 0-100% security posture score that aggregates recommended actions across identity, devices, apps, and data?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Secure Score"},{"id":"b","text":"Microsoft Compliance Manager"},{"id":"c","text":"Microsoft Entra License usage"},{"id":"d","text":"Microsoft 365 Apps health dashboard"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft Secure Score aggregates security recommendations into a percentage score and tracks improvement actions. Compliance Manager scores compliance posture. License usage and Apps health are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-secure-score","label":"Microsoft Learn — Microsoft Secure Score"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft 365 capability gives a single 0-100% security posture score that aggregates recommended actions across identity, devices, apps, and data?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want Defender XDR to automatically investigate alerts and remediate confirmed malicious entities (e.g. delete a file, isolate a device) without analyst intervention for low-risk cases. Which capability provides this?$ms102r$, $ms102r$[{"id":"a","text":"Automated investigation and response (AIR)"},{"id":"b","text":"Manual playbook in Microsoft Sentinel only"},{"id":"c","text":"Conditional Access"},{"id":"d","text":"Microsoft Purview communication compliance"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$AIR runs automated investigations on alerts and applies remediation actions based on configured automation levels. Sentinel playbooks are a different (paid SIEM) product. CA controls sign-ins. Purview communication compliance reviews messages.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/automated-investigations","label":"Microsoft Learn — Automated investigation and response in Microsoft Defender for Endpoint"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want Defender XDR to automatically investigate alerts and remediate confirmed malicious entities (e.g. delete a file, isolate a device) without analyst intervention for low-risk cases. Which capability provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which feature in Defender for Office 365 detonates email attachments in a sandbox before delivery to evaluate whether they exhibit malicious behavior?$ms102r$, $ms102r$[{"id":"a","text":"Safe Attachments"},{"id":"b","text":"Safe Links"},{"id":"c","text":"Anti-spam policy"},{"id":"d","text":"Inbox rules"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Safe Attachments opens attachments in a virtual environment to detect zero-day behaviors before delivery. Safe Links protects URLs at click time. Anti-spam scores spam. Inbox rules are mailbox-level rules, not threat protection.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-attachments-about","label":"Microsoft Learn — Safe Attachments in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which feature in Defender for Office 365 detonates email attachments in a sandbox before delivery to evaluate whether they exhibit malicious behavior?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Microsoft's recommended posture for outbound mail authentication is to publish a DMARC record with which policy after a monitoring period?$ms102r$, $ms102r$[{"id":"a","text":"p=none indefinitely"},{"id":"b","text":"p=quarantine or p=reject once SPF and DKIM align cleanly"},{"id":"c","text":"p=allow"},{"id":"d","text":"Remove the DMARC record entirely"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Best practice is to start with p=none for visibility, then move to p=quarantine and finally p=reject once SPF/DKIM are passing and aligned. Staying at p=none provides no enforcement. p=allow is not a valid DMARC value.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dmarc-configure","label":"Microsoft Learn — Use DMARC to validate email"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Microsoft's recommended posture for outbound mail authentication is to publish a DMARC record with which policy after a monitoring period?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A device covered by Defender for Endpoint shows a high-confidence alert that a process is exfiltrating data. As an analyst, which action isolates the device from network communication while preserving its connection to Defender for Endpoint cloud service?$ms102r$, $ms102r$[{"id":"a","text":"Use \"Isolate device\" from the device page in the Defender portal"},{"id":"b","text":"Remove the device from Microsoft Entra ID"},{"id":"c","text":"Apply a Conditional Access \"block\" policy targeting the user"},{"id":"d","text":"Run Disk Cleanup remotely"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The "Isolate device" action in the Defender portal cuts general network access while keeping the agent-to-service channel up so analysts can still investigate and remediate. Removing the Entra object, applying CA blocks, or running Disk Cleanup do not provide forensic isolation.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A device covered by Defender for Endpoint shows a high-confidence alert that a process is exfiltrating data. As an analyst, which action isolates the device from network communication while preserving its connection to Defender for Endpoint cloud service?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Where do you view and configure the Microsoft Security Exposure Management initiatives that prioritize the most impactful posture improvements across the attack surface?$ms102r$, $ms102r$[{"id":"a","text":"Exposure management section of the Microsoft Defender portal"},{"id":"b","text":"Microsoft Purview portal"},{"id":"c","text":"Microsoft Entra admin center"},{"id":"d","text":"Azure Cost Management"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft Security Exposure Management lives in the Defender portal's Exposure management section and surfaces initiatives that combine Secure Score, vulnerabilities, and other signals. Purview is compliance; Entra is identity; Cost Management is billing.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/security-exposure-management/microsoft-security-exposure-management","label":"Microsoft Learn — Microsoft Security Exposure Management"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Where do you view and configure the Microsoft Security Exposure Management initiatives that prioritize the most impactful posture improvements across the attack surface?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 1, $ms102r$SINGLE$ms102r$::"QType", $ms102r$In the Microsoft Purview portal, where do you create a data loss prevention policy that prevents users from sharing credit card numbers in Microsoft Teams chats?$ms102r$, $ms102r$[{"id":"a","text":"Solutions > Data Loss Prevention > Policies > Create policy"},{"id":"b","text":"Solutions > Information Protection > Labels"},{"id":"c","text":"Solutions > Records management > File plan"},{"id":"d","text":"Solutions > Audit > New search"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$DLP policies are created under Solutions > Data Loss Prevention > Policies and can target Teams chats, mailboxes, sites, and endpoints. Information Protection is for sensitivity labels. Records management is for retention. Audit is for activity search.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp","label":"Microsoft Learn — Data Loss Prevention overview"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-create-deploy-policy","label":"Microsoft Learn — Create and deploy a data loss prevention policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$In the Microsoft Purview portal, where do you create a data loss prevention policy that prevents users from sharing credit card numbers in Microsoft Teams chats?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want a DLP policy to detect U.S. Social Security Numbers in SharePoint Online with high confidence. Which built-in classifier should the DLP rule match on?$ms102r$, $ms102r$[{"id":"a","text":"A sensitive information type for \"U.S. Social Security Number (SSN)\" with high confidence"},{"id":"b","text":"A retention label called \"SSN\""},{"id":"c","text":"A custom Conditional Access named location"},{"id":"d","text":"A communication compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sensitive information types (SITs) like "U.S. Social Security Number" are the built-in classifiers DLP rules match. Retention labels apply lifecycle, not detection. CA named locations are network conditions. Communication compliance reviews internal messages.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitive-information-type-learn-about","label":"Microsoft Learn — Sensitive information types in Microsoft Purview"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-create-deploy-policy","label":"Microsoft Learn — Create and deploy a data loss prevention policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want a DLP policy to detect U.S. Social Security Numbers in SharePoint Online with high confidence. Which built-in classifier should the DLP rule match on?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want documents tagged "Confidential" to be encrypted, watermarked, and unable to be forwarded outside the organization. Which Purview feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Sensitivity labels with encryption, content marking, and \"Do not forward\" rights"},{"id":"b","text":"Retention labels with delete-only actions"},{"id":"c","text":"eDiscovery legal holds"},{"id":"d","text":"Insider risk management policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sensitivity labels apply encryption (Azure Information Protection / Microsoft Purview Information Protection), visual markings, and usage rights such as "Do not forward". Retention labels manage lifecycle; eDiscovery is for legal investigations; insider risk detects risky activities.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitivity-labels","label":"Microsoft Learn — Learn about sensitivity labels"},{"url":"https://learn.microsoft.com/en-us/purview/create-sensitivity-labels","label":"Microsoft Learn — Publish sensitivity labels by creating a label policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want documents tagged "Confidential" to be encrypted, watermarked, and unable to be forwarded outside the organization. Which Purview feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to retain all Exchange mailboxes and SharePoint sites for at least 7 years to satisfy a regulator, regardless of user deletion. Which Purview feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"A retention policy targeting Exchange and SharePoint with retain-only for 7 years"},{"id":"b","text":"A sensitivity label with encryption"},{"id":"c","text":"A DLP policy that blocks delete"},{"id":"d","text":"An eDiscovery (Standard) case"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Retention policies retain content for a specified duration across multiple workloads (Exchange, SharePoint, OneDrive, Teams). Sensitivity labels protect, not retain. DLP rules cannot enforce a deletion hold. eDiscovery cases are matter-specific.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/retention","label":"Microsoft Learn — Learn about retention policies and retention labels"},{"url":"https://learn.microsoft.com/en-us/purview/create-retention-policies","label":"Microsoft Learn — Create and configure retention policies"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to retain all Exchange mailboxes and SharePoint sites for at least 7 years to satisfy a regulator, regardless of user deletion. Which Purview feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Purview retention.$ms102r$, $ms102r$[{"id":"a","text":"A retention policy can preserve content for a fixed period and then delete it."},{"id":"b","text":"When retention and deletion conflict on the same item, retention wins (content is preserved)."},{"id":"c","text":"Retention labels can be applied manually by users or automatically using conditions."},{"id":"d","text":"A retention policy can encrypt content with sensitivity-label encryption."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$Retention policies handle retain+delete, retention wins over delete by design, and retention labels can be applied manually or via conditions. Encryption is provided by sensitivity labels, not retention.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/retention","label":"Microsoft Learn — Learn about retention policies and retention labels"},{"url":"https://learn.microsoft.com/en-us/purview/file-plan-manager","label":"Microsoft Learn — Create retention labels and apply them in apps"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Purview retention.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A legal hold has been requested on the mailbox of an employee under investigation. The mailbox must be preserved even if the user attempts to delete content. Which approach is correct?$ms102r$, $ms102r$[{"id":"a","text":"Create an eDiscovery (Standard or Premium) case, add the custodian, and place a hold on the mailbox"},{"id":"b","text":"Apply a DLP policy that blocks deletion"},{"id":"c","text":"Move the mailbox to In-Place Archive"},{"id":"d","text":"Apply an Insider risk management policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$eDiscovery cases (Standard/Premium) support legal holds that preserve mailbox content even if the user deletes it. DLP blocks transmissions, not deletions. In-Place Archive is for mailbox tiering, not hold. Insider risk detects risky activities, not preservation.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/ediscovery","label":"Microsoft Learn — Microsoft Purview eDiscovery solutions"},{"url":"https://learn.microsoft.com/en-us/purview/ediscovery-standard-get-started","label":"Microsoft Learn — Get started with eDiscovery (Standard)"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A legal hold has been requested on the mailbox of an employee under investigation. The mailbox must be preserved even if the user attempts to delete content. Which approach is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A regulator requires a 10-year audit retention with the ability to investigate intelligent insights such as MailItemsAccessed and Send-on-behalf events. Which capability provides these advanced events and extended retention?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Purview Audit (Premium)"},{"id":"b","text":"Microsoft Purview Audit (Standard)"},{"id":"c","text":"Microsoft 365 message trace"},{"id":"d","text":"Microsoft Entra sign-in logs"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Purview Audit (Premium) provides extended retention (1 year, extensible to 10) and advanced audit events such as MailItemsAccessed. Audit (Standard) has shorter retention and fewer events. Message trace is mail-flow only. Entra sign-in logs only cover sign-ins.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/audit-premium","label":"Microsoft Learn — Microsoft Purview Audit (Premium)"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A regulator requires a 10-year audit retention with the ability to investigate intelligent insights such as MailItemsAccessed and Send-on-behalf events. Which capability provides these advanced events and extended retention?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to detect employees emailing large volumes of internal files to personal accounts shortly before resigning. Which Microsoft Purview feature is designed for this scenario?$ms102r$, $ms102r$[{"id":"a","text":"Insider risk management with the \"Data leaks by departing users\" template"},{"id":"b","text":"Microsoft Defender for Endpoint vulnerability assessment"},{"id":"c","text":"Communication compliance review of all internal emails"},{"id":"d","text":"eDiscovery (Premium) review-set analytics"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Insider risk management templates such as "Data leaks by departing users" combine HR signals (resignation date) with file/email activity to flag risky actions. The other options address different concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/insider-risk-management","label":"Microsoft Learn — Learn about insider risk management"},{"url":"https://learn.microsoft.com/en-us/purview/insider-risk-management-policies","label":"Microsoft Learn — Insider risk management policies"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p1$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to detect employees emailing large volumes of internal files to personal accounts shortly before resigning. Which Microsoft Purview feature is designed for this scenario?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$After you add and verify the domain fabrikam.com to your Microsoft 365 tenant, mail flow to user@fabrikam.com still fails with a non-delivery report. Which DNS record is most likely missing or incorrect?$ms102r$, $ms102r$[{"id":"a","text":"The MX record pointing to the Exchange Online host (fabrikam-com.mail.protection.outlook.com)"},{"id":"b","text":"A CNAME pointing to outlook.office.com"},{"id":"c","text":"An A record for the apex domain"},{"id":"d","text":"A TXT verification record"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$For Exchange Online to receive mail for a custom domain, the MX record must point to <tenant>.mail.protection.outlook.com. The verification TXT is needed only at the verification step. Apex A and login CNAMEs are not the cause of NDRs.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/get-help-with-domains/create-dns-records-at-any-dns-hosting-provider","label":"Microsoft Learn — Create DNS records at any DNS hosting provider"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/setup/add-domain","label":"Microsoft Learn — Add a domain to Microsoft 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$After you add and verify the domain fabrikam.com to your Microsoft 365 tenant, mail flow to user@fabrikam.com still fails with a non-delivery report. Which DNS record is most likely missing or incorrect?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your CFO needs read-only insight into every user's licenses and usage, but should not be able to change settings. Which role is most appropriate?$ms102r$, $ms102r$[{"id":"a","text":"Global Reader"},{"id":"b","text":"Billing Administrator"},{"id":"c","text":"User Administrator"},{"id":"d","text":"License Administrator"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Global Reader provides read-only access across the admin centers, ideal for executives needing visibility without change rights. Billing/License/User Administrators can make changes within their scope.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your CFO needs read-only insight into every user's licenses and usage, but should not be able to change settings. Which role is most appropriate?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You assigned Office 365 E3 to a 5,000-user group via group-based licensing. Two users in that group could not have a license applied because of a service plan dependency. Where can you investigate the error?$ms102r$, $ms102r$[{"id":"a","text":"The \"Licenses\" page of the group in Microsoft Entra ID, which shows reprocessing status and per-user errors"},{"id":"b","text":"The user's mailbox in Outlook"},{"id":"c","text":"The Defender XDR portal"},{"id":"d","text":"Service health"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Group-based licensing reports per-user errors on the group's Licenses page in Entra ID, including service-plan conflicts. Outlook, Defender, and Service Health are unrelated to licensing assignment errors.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/users/licensing-groups-assign","label":"Microsoft Learn — Group-based licensing in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/manage/assign-licenses-to-users","label":"Microsoft Learn — Assign licenses to users"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You assigned Office 365 E3 to a 5,000-user group via group-based licensing. Two users in that group could not have a license applied because of a service plan dependency. Where can you investigate the error?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You receive a Message center post announcing a feature change rolling out in 30 days. Which audience should you notify so that affected users can be prepared?$ms102r$, $ms102r$[{"id":"a","text":"No one — Message center is for admins only"},{"id":"b","text":"The targeted users and groups noted in the post, by forwarding the post via email or scheduled in the admin center"},{"id":"c","text":"The Global Administrators of partner tenants"},{"id":"d","text":"Microsoft support"}]$ms102r$::jsonb, $ms102r$["b"]$ms102r$::jsonb, $ms102r$Message center posts describe the impact area; the recommendation is to forward to affected users or to broader IT stakeholders. Posts are for admins, but the *impact* extends to users. Partner tenants get their own posts. Microsoft support is not the recipient.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/manage/message-center","label":"Microsoft Learn — Stay on top of changes with Message center"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You receive a Message center post announcing a feature change rolling out in 30 days. Which audience should you notify so that affected users can be prepared?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to deploy Microsoft 365 Apps with semi-annual feature updates and quarterly security baselines for line-of-business compatibility teams. Which update channel matches?$ms102r$, $ms102r$[{"id":"a","text":"Semi-Annual Enterprise Channel"},{"id":"b","text":"Current Channel"},{"id":"c","text":"Monthly Enterprise Channel"},{"id":"d","text":"Beta Channel"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Semi-Annual Enterprise Channel delivers new features every 6 months (with security updates each month) and is the slowest production channel — best suited for environments requiring extensive compatibility testing.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/deployoffice/overview-update-channels","label":"Microsoft Learn — Overview of update channels for Microsoft 365 Apps"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to deploy Microsoft 365 Apps with semi-annual feature updates and quarterly security baselines for line-of-business compatibility teams. Which update channel matches?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports that the Outlook app on their managed iPhone shows their corporate mailbox without prompting for sign-in after they were enrolled in Intune. Which feature most likely provided the seamless experience?$ms102r$, $ms102r$[{"id":"a","text":"A device configuration profile pushing the Outlook email account settings"},{"id":"b","text":"A retention policy applied to the mailbox"},{"id":"c","text":"A DLP policy on Outlook"},{"id":"d","text":"A Defender for Endpoint onboarding package"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Intune can push email-account configuration to Outlook on iOS via a device configuration profile, pre-populating the user's sign-in. Retention/DLP policies are content governance. Defender onboarding is endpoint protection.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/configuration/device-profiles","label":"Microsoft Learn — Apply features and settings on devices with Intune configuration profiles"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports that the Outlook app on their managed iPhone shows their corporate mailbox without prompting for sign-in after they were enrolled in Intune. Which feature most likely provided the seamless experience?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Intune compliance policies.$ms102r$, $ms102r$[{"id":"a","text":"They can require a minimum operating-system version."},{"id":"b","text":"They can require disk encryption (BitLocker or FileVault)."},{"id":"c","text":"They can directly install or remove applications."},{"id":"d","text":"Their compliance state can be referenced as a Conditional Access grant control (\"Require device to be marked as compliant\")."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$Compliance policies define health requirements (OS version, encryption, AV, jailbreak detection, etc.). App install/removal is the role of app deployments, not compliance policies. The compliance result is what CA references.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/device-compliance-get-started","label":"Microsoft Learn — Use device compliance policies in Intune"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Intune compliance policies.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to migrate ten thousand Windows 11 devices to a self-deploying setup where the device automatically joins Microsoft Entra and enrolls into Intune with no user interaction. Which Autopilot deployment mode meets this requirement?$ms102r$, $ms102r$[{"id":"a","text":"Self-deploying mode"},{"id":"b","text":"User-driven mode"},{"id":"c","text":"Pre-provisioning (white glove) mode"},{"id":"d","text":"Existing-device redeploy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Self-deploying mode performs Entra join + Intune enrollment without any user input — ideal for kiosks/digital signage. User-driven requires a user sign-in. Pre-provisioning is IT-staged. Existing-device redeploy targets enrolled devices to reset state.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/autopilot/windows-autopilot","label":"Microsoft Learn — Windows Autopilot overview"},{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to migrate ten thousand Windows 11 devices to a self-deploying setup where the device automatically joins Microsoft Entra and enrolls into Intune with no user interaction. Which Autopilot deployment mode meets this requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to grant a partner administrator temporary delegated rights to operate as your Helpdesk Administrator for two weeks. Which mechanism is correct?$ms102r$, $ms102r$[{"id":"a","text":"GDAP with a Helpdesk Administrator role and an explicit expiration date"},{"id":"b","text":"A custom admin role with no expiration"},{"id":"c","text":"A shared mailbox"},{"id":"d","text":"A Conditional Access policy excluding the partner"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$GDAP allows specifying the Entra roles and an expiration. Custom roles without expiration grant standing access. Shared mailboxes provide mail collaboration, not admin rights. CA does not grant administrative roles.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/partner-center/customers/gdap-introduction","label":"Microsoft Learn — Delegated administration and GDAP"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to grant a partner administrator temporary delegated rights to operate as your Helpdesk Administrator for two weeks. Which mechanism is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A managed service provider wants to apply baseline security configurations (MFA, default policies) across all 50 of their managed Microsoft 365 SMB tenants from one place. Which service should they use?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft 365 Lighthouse"},{"id":"b","text":"Microsoft Sentinel multi-workspace"},{"id":"c","text":"Microsoft Defender for Cloud"},{"id":"d","text":"Microsoft Entra Domain Services"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Lighthouse provides multi-tenant management for SMB customers with baseline configuration, posture, and remediation. Sentinel multi-workspace is a SIEM scope. Defender for Cloud is Azure workload protection. Entra Domain Services is managed AD.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/lighthouse/m365-lighthouse-overview","label":"Microsoft Learn — Multi-tenant management with Microsoft 365 Lighthouse"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A managed service provider wants to apply baseline security configurations (MFA, default policies) across all 50 of their managed Microsoft 365 SMB tenants from one place. Which service should they use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user requires the Exchange Administrator role only when performing an audit. They should not have standing privileges. After enabling PIM, which sign-in setting BEST ensures their activation is logged and approved by a peer?$ms102r$, $ms102r$[{"id":"a","text":"Configure the role assignment as eligible and require approval and MFA for activation"},{"id":"b","text":"Make them a permanent member of Global Administrators"},{"id":"c","text":"Disable MFA for their account"},{"id":"d","text":"Grant tenant access only from the corporate office IP"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PIM eligible assignments allow just-in-time activation with required MFA and approval, and the activation is logged. Permanent Global Admin breaks least privilege; disabling MFA weakens security; IP gating alone does not provide approval/audit.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user requires the Exchange Administrator role only when performing an audit. They should not have standing privileges. After enabling PIM, which sign-in setting BEST ensures their activation is logged and approved by a peer?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft 365 admin center surface is the authoritative source for tenant-wide service incidents and post-incident reports?$ms102r$, $ms102r$[{"id":"a","text":"Service health"},{"id":"b","text":"Reports > Usage"},{"id":"c","text":"Reports > Productivity Score"},{"id":"d","text":"Settings > Org settings"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Service health is the authoritative source for active incidents, advisories, history, and post-incident reports. Usage and Productivity Score are usage analytics. Org settings configure services, not incidents.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/enterprise/view-service-health","label":"Microsoft Learn — How to check Microsoft 365 service health"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft 365 admin center surface is the authoritative source for tenant-wide service incidents and post-incident reports?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to delegate management of users in only the Australia region to a regional admin team. The team must NOT see users from other countries. Which feature satisfies this requirement?$ms102r$, $ms102r$[{"id":"a","text":"A Microsoft Entra administrative unit containing the Australia users, with the team scoped as User Administrator on that unit"},{"id":"b","text":"A Conditional Access policy filtered to Australia"},{"id":"c","text":"A retention policy targeting Australia"},{"id":"d","text":"A Defender for Cloud Apps policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Administrative units scope Entra role assignments to a subset of users/groups/devices — exactly the regional delegation scenario. CA gates sign-ins. Retention and Defender for Cloud Apps do not delegate user management.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/administrative-units","label":"Microsoft Learn — Administrative units in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to delegate management of users in only the Australia region to a regional admin team. The team must NOT see users from other countries. Which feature satisfies this requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft 365 admin center insight presents an organization's "Communication, Meetings, Content collaboration, Teamwork, and Mobility" people-experience score?$ms102r$, $ms102r$[{"id":"a","text":"Adoption Score"},{"id":"b","text":"Service health"},{"id":"c","text":"Secure Score"},{"id":"d","text":"Compliance Score"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Adoption Score (formerly Productivity Score) measures the people experience across Microsoft 365. Service health is incident status. Secure Score is security posture. Compliance Score is governance posture.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/adoption/adoption-score","label":"Microsoft Learn — Microsoft 365 adoption score"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft 365 admin center insight presents an organization's "Communication, Meetings, Content collaboration, Teamwork, and Mobility" people-experience score?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to control which users can self-enroll personal Windows devices into Intune for "Bring Your Own Device" access. Which Intune setting is most relevant?$ms102r$, $ms102r$[{"id":"a","text":"Enrollment restrictions that allow or block personal device platforms per user group"},{"id":"b","text":"A Conditional Access named location"},{"id":"c","text":"A communication compliance review"},{"id":"d","text":"Group-based licensing"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Intune enrollment restrictions can permit or block personal (BYO) devices per platform and user group. Named locations are network conditions; communication compliance reviews messages; licensing is unrelated to platform restrictions.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to control which users can self-enroll personal Windows devices into Intune for "Bring Your Own Device" access. Which Intune setting is most relevant?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to deploy a specific Microsoft 365 Apps build (a known-good version) to a pilot ring before promoting it tenant-wide. Which feature in the Microsoft 365 Apps admin center supports this?$ms102r$, $ms102r$[{"id":"a","text":"Servicing profiles (Microsoft 365 Apps admin center)"},{"id":"b","text":"Microsoft Defender for Endpoint"},{"id":"c","text":"A retention policy"},{"id":"d","text":"Microsoft Entra access reviews"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Servicing profiles in the Microsoft 365 Apps admin center pin builds to user groups and enable controlled rollouts. Defender, retention, and access reviews are unrelated to Apps build management.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/deployoffice/admincenter/overview","label":"Microsoft Learn — Overview of the Microsoft 365 Apps admin center"},{"url":"https://learn.microsoft.com/en-us/deployoffice/deployment-guide-microsoft-365-apps","label":"Microsoft Learn — Deployment guide for Microsoft 365 Apps"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to deploy a specific Microsoft 365 Apps build (a known-good version) to a pilot ring before promoting it tenant-wide. Which feature in the Microsoft 365 Apps admin center supports this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want a user to be a Global Administrator only for the next 4 hours to complete a configuration change. They will need MFA and a justification reason on activation. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra Privileged Identity Management (PIM)"},{"id":"b","text":"Granting standing Global Administrator and removing it later"},{"id":"c","text":"A Conditional Access policy"},{"id":"d","text":"A device compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PIM is the just-in-time, time-bound, approval-and-MFA-gated activation system for privileged Entra roles. Standing assignments violate least privilege. CA controls sign-ins; compliance policies evaluate devices.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want a user to be a Global Administrator only for the next 4 hours to complete a configuration change. They will need MFA and a justification reason on activation. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$When a new Microsoft 365 tenant is created from sign-up, the default fallback domain takes which form?$ms102r$, $ms102r$[{"id":"a","text":"<tenantname>.onmicrosoft.com"},{"id":"b","text":"<tenantname>.azurewebsites.net"},{"id":"c","text":"<tenantname>.cloudapp.net"},{"id":"d","text":"<tenantname>.local"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The default fallback for a new Microsoft 365 tenant is <tenantname>.onmicrosoft.com. Azurewebsites.net is for App Service, cloudapp.net is legacy Cloud Services, and .local is an on-prem AD pattern.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/setup/add-domain","label":"Microsoft Learn — Add a domain to Microsoft 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$When a new Microsoft 365 tenant is created from sign-up, the default fallback domain takes which form?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to invite an external contractor to collaborate on a SharePoint site. The contractor uses an existing Microsoft Entra account in another tenant. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra B2B collaboration with a guest invitation"},{"id":"b","text":"A federated trust with the contractor's domain"},{"id":"c","text":"Microsoft Entra Domain Services"},{"id":"d","text":"A service principal"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$B2B issues guest invitations that let external users sign in with their own identity and access your shared resources. Federation is a complex on-prem trust; Entra Domain Services is a managed AD; service principals are app identities.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to invite an external contractor to collaborate on a SharePoint site. The contractor uses an existing Microsoft Entra account in another tenant. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A hybrid identity solution uses Microsoft Entra Cloud Sync (rather than Entra Connect Sync). Which scenario is BEST served by Cloud Sync?$ms102r$, $ms102r$[{"id":"a","text":"Synchronizing disconnected forests and small AD environments with simplified deployment"},{"id":"b","text":"Synchronizing complex device-write-back scenarios"},{"id":"c","text":"Real-time replication of certificates from CA"},{"id":"d","text":"Push-based DKIM key rotation"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Cloud Sync uses lightweight agents and is well suited to multiple disconnected forests, smaller AD scenarios, and simpler deployments. Complex hybrid (device write-back, etc.) still needs Entra Connect Sync. CAs and DKIM rotation are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/cloud-sync/what-is-cloud-sync","label":"Microsoft Learn — What is Microsoft Entra Cloud Sync?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sync-whatis","label":"Microsoft Learn — Microsoft Entra Connect Sync: Understand and customize synchronization"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A hybrid identity solution uses Microsoft Entra Cloud Sync (rather than Entra Connect Sync). Which scenario is BEST served by Cloud Sync?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Entra Conditional Access named locations.$ms102r$, $ms102r$[{"id":"a","text":"They can be defined as IPv4/IPv6 ranges."},{"id":"b","text":"They can be defined as countries/regions based on the sign-in IP."},{"id":"c","text":"They can be marked as trusted, which affects the sign-in risk calculation."},{"id":"d","text":"They can install software on the device."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$Named locations support IP ranges, country/region lists, and a trusted flag. They are policy targets — they do not push software (that's Intune/SCCM).$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/location-condition","label":"Microsoft Learn — Named locations in Conditional Access"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Entra Conditional Access named locations.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to require Microsoft Authenticator number-matching MFA when users access a sensitive Power BI report. Which feature lets you require a specific authentication strength?$ms102r$, $ms102r$[{"id":"a","text":"Conditional Access authentication strengths"},{"id":"b","text":"Self-service password reset settings"},{"id":"c","text":"Microsoft Entra Domain Services"},{"id":"d","text":"Tenant access policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Authentication strengths in Conditional Access let you require specific methods (e.g. phishing-resistant MFA, number matching). SSPR is about password reset; Entra DS is managed AD; "tenant access policies" is not a CA term.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to require Microsoft Authenticator number-matching MFA when users access a sensitive Power BI report. Which feature lets you require a specific authentication strength?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A new joiner needs access to multiple SharePoint sites, a Teams team, and an Azure subscription. You want managers to request the bundle and have it provisioned with one approval. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra entitlement management access packages"},{"id":"b","text":"Conditional Access policies"},{"id":"c","text":"Privileged Identity Management activations"},{"id":"d","text":"Group-based licensing"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Entitlement management access packages bundle resources and an approval workflow for self-service access. CA controls sign-ins, PIM activates roles, group-based licensing assigns licenses — none bundle multiple resources for request.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/entitlement-management-overview","label":"Microsoft Learn — What is entitlement management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A new joiner needs access to multiple SharePoint sites, a Teams team, and an Azure subscription. You want managers to request the bundle and have it provisioned with one approval. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want users to be blocked when Entra ID Protection determines their account is high-risk (e.g. leaked credentials), and they must clean up before access is restored. Which policy should you configure?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy that targets the high user-risk condition with a Block grant control, requiring admin remediation"},{"id":"b","text":"A retention policy on the user's mailbox"},{"id":"c","text":"A DLP policy with a custom SIT"},{"id":"d","text":"A Defender for Cloud Apps OAuth app policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$User-risk Conditional Access policies block high-risk users (or force password reset). Retention, DLP, and OAuth governance address content and apps, not identity risk.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want users to be blocked when Entra ID Protection determines their account is high-risk (e.g. leaked credentials), and they must clean up before access is restored. Which policy should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You enabled SSPR for a group of pilot users and want them registered for the right authentication methods before they need to reset. Which approach automates registration?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy or registration campaign requiring users to register authentication methods at next sign-in"},{"id":"b","text":"Asking each user manually via email"},{"id":"c","text":"Disabling all sign-ins until they register"},{"id":"d","text":"Removing all MFA from accounts"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$A registration campaign (or a CA policy with the "Register security information" action) prompts users to register at next sign-in. Manual asks scale poorly. Disabling sign-ins blocks work. Removing MFA weakens security.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-sspr-howitworks","label":"Microsoft Learn — How it works: Microsoft Entra self-service password reset"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You enabled SSPR for a group of pilot users and want them registered for the right authentication methods before they need to reset. Which approach automates registration?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$In a Microsoft Entra Connect Sync deployment, which authentication option ensures that on-premises AD continues to make the authentication decision (no password hash in the cloud) while supporting SSO from Entra-joined devices?$ms102r$, $ms102r$[{"id":"a","text":"Pass-through authentication with seamless SSO"},{"id":"b","text":"Cloud-only password hash sync"},{"id":"c","text":"Federation with AD FS"},{"id":"d","text":"Microsoft Entra B2B"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PTA validates each sign-in against on-prem AD via lightweight agents, keeping the decision on-prem. Federation also keeps decisions on-prem but is more complex and typically not recommended for new deployments. PHS stores hashes in the cloud; B2B is unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-pta","label":"Microsoft Learn — Microsoft Entra pass-through authentication"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-fed","label":"Microsoft Learn — Federation with AD FS and Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$In a Microsoft Entra Connect Sync deployment, which authentication option ensures that on-premises AD continues to make the authentication decision (no password hash in the cloud) while supporting SSO from Entra-joined devices?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to grant a group of contractors access to a Microsoft 365 app, but only when sign-in originates from an unmanaged device — and to enforce session controls that prevent download. Which combination is required?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy with session controls (Use Conditional Access App Control through Microsoft Defender for Cloud Apps) targeting the contractor group"},{"id":"b","text":"Group-based licensing alone"},{"id":"c","text":"Federation only"},{"id":"d","text":"Self-service password reset"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CA App Control (powered by Defender for Cloud Apps) provides session controls — including block-download — for unmanaged-device sessions. Licensing, federation, and SSPR do not implement these session controls.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to grant a group of contractors access to a Microsoft 365 app, but only when sign-in originates from an unmanaged device — and to enforce session controls that prevent download. Which combination is required?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A new policy must require a Microsoft Entra ID Protection sign-in risk of medium or higher to trigger MFA, but only for cloud apps; native sign-ins to Windows should not be affected. Which target is correct?$ms102r$, $ms102r$[{"id":"a","text":"Set the Conditional Access policy \"Cloud apps or actions\" to All cloud apps (or specific apps) and use sign-in risk condition"},{"id":"b","text":"Use a per-user MFA setting"},{"id":"c","text":"Add a retention policy"},{"id":"d","text":"Enable security defaults"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CA policies target cloud apps and let you scope by sign-in risk. Per-user MFA does not respect risk. Retention policies are unrelated. Security defaults are tenant-wide with no risk scoping.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A new policy must require a Microsoft Entra ID Protection sign-in risk of medium or higher to trigger MFA, but only for cloud apps; native sign-ins to Windows should not be affected. Which target is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to enforce reauthentication every 4 hours for users accessing a sensitive web app. Which Conditional Access session control should you configure?$ms102r$, $ms102r$[{"id":"a","text":"Sign-in frequency = 4 hours on the Conditional Access policy"},{"id":"b","text":"Persistent browser session = always"},{"id":"c","text":"Pass-through authentication enabled"},{"id":"d","text":"Group-based licensing"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sign-in frequency forces re-authentication after the specified interval. Persistent browser session does the opposite. PTA is hybrid auth. Licensing is unrelated to session length.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-conditional-access-policies","label":"Microsoft Learn — Build a Conditional Access policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to enforce reauthentication every 4 hours for users accessing a sensitive web app. Which Conditional Access session control should you configure?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which feature, when activated, requires MFA for risky sign-in patterns AND auto-remediates user risk by forcing a password change — but ONLY for licensed users?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra ID Protection risk-based Conditional Access policies (require Entra ID P2 licensing)"},{"id":"b","text":"Security defaults"},{"id":"c","text":"Per-user MFA"},{"id":"d","text":"Microsoft Entra Domain Services"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ID Protection sign-in/user risk policies require Entra ID P2 licensing. Security defaults are free but not risk-conditional. Per-user MFA is not risk-aware. Entra DS is unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which feature, when activated, requires MFA for risky sign-in patterns AND auto-remediates user risk by forcing a password change — but ONLY for licensed users?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to roll out passwordless authentication using Windows Hello for Business across the enterprise, but only for users who currently have a Microsoft Authenticator registered. Where do you configure both the enablement and the targeted group?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra ID > Security > Authentication methods > Policies > Windows Hello for Business, scoped to the chosen group"},{"id":"b","text":"Per-user MFA Service Settings only"},{"id":"c","text":"A Conditional Access policy with named locations"},{"id":"d","text":"Microsoft Entra Connect Sync filters"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Authentication methods policy controls which methods are enabled and to which groups. Per-user MFA service settings predate this and cannot scope WHfB. CA and Connect Sync filters are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-passwordless","label":"Microsoft Learn — Passwordless authentication options for Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to roll out passwordless authentication using Windows Hello for Business across the enterprise, but only for users who currently have a Microsoft Authenticator registered. Where do you configure both the enablement and the targeted group?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A new external partner uses an organization that is NOT a Microsoft Entra tenant — only personal email accounts. You still want them to access a Microsoft Teams team in your tenant with their existing email identity. Which Microsoft Entra capability supports this?$ms102r$, $ms102r$[{"id":"a","text":"B2B collaboration with email one-time passcode authentication for non-Entra guests"},{"id":"b","text":"B2B direct connect"},{"id":"c","text":"Federation with the partner's on-prem AD"},{"id":"d","text":"A service principal granted to the partner"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Email one-time passcode (OTP) lets external users without an Entra/Microsoft account sign in as B2B guests using a code sent to their email. B2B direct connect is for Microsoft 365 cross-tenant Teams. Federation/SPNs are not the right fit.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A new external partner uses an organization that is NOT a Microsoft Entra tenant — only personal email accounts. You still want them to access a Microsoft Teams team in your tenant with their existing email identity. Which Microsoft Entra capability supports this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to migrate from on-premises AD FS federation to managed cloud authentication while keeping the option to roll back. Which staged-rollout capability does Microsoft Entra Connect offer?$ms102r$, $ms102r$[{"id":"a","text":"Staged Rollout to move groups of users from federation to PHS or PTA in a controlled way"},{"id":"b","text":"Tenant-wide replace federation in one shot"},{"id":"c","text":"B2B collaboration migration"},{"id":"d","text":"Microsoft Entra Domain Services replacement"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Staged Rollout in Entra ID lets you cut over groups of federated users to PHS or PTA gradually, with rollback. The other options are not the migration pattern.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-fed","label":"Microsoft Learn — Federation with AD FS and Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-password-hash-synchronization","label":"Microsoft Learn — Implement password hash synchronization with Microsoft Entra Connect Sync"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-pta","label":"Microsoft Learn — Microsoft Entra pass-through authentication"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to migrate from on-premises AD FS federation to managed cloud authentication while keeping the option to roll back. Which staged-rollout capability does Microsoft Entra Connect offer?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A SOC analyst notices repeated sign-in attempts to a low-value SaaS app with valid usernames but wrong passwords from many IPs — a password spray pattern. Which Microsoft Entra capability automatically labels these sign-ins as risky and can require remediation?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra ID Protection (sign-in risk detection — \"Password spray\")"},{"id":"b","text":"Conditional Access named locations"},{"id":"c","text":"Per-user MFA enabled for the user"},{"id":"d","text":"Self-service password reset"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$ID Protection includes password-spray detection that elevates sign-in risk. CA named locations are a static condition. Per-user MFA and SSPR are not risk-based.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A SOC analyst notices repeated sign-in attempts to a low-value SaaS app with valid usernames but wrong passwords from many IPs — a password spray pattern. Which Microsoft Entra capability automatically labels these sign-ins as risky and can require remediation?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft Entra Identity Governance feature lets you define HR-event-triggered "joiner / mover / leaver" automation, such as creating a user, granting access packages, and disabling them at termination?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra lifecycle workflows"},{"id":"b","text":"Microsoft Entra Domain Services"},{"id":"c","text":"Microsoft Entra B2B direct connect"},{"id":"d","text":"Conditional Access reporting-only mode"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Lifecycle workflows orchestrate joiner/mover/leaver tasks tied to attributes/dates and can invoke access-package operations. Entra DS is a managed domain; B2B direct connect is Teams cross-tenant; reporting-only is a CA policy mode.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/entitlement-management-overview","label":"Microsoft Learn — What is entitlement management?"},{"url":"https://learn.microsoft.com/en-us/entra/id-governance/access-reviews-overview","label":"Microsoft Learn — What are access reviews?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft Entra Identity Governance feature lets you define HR-event-triggered "joiner / mover / leaver" automation, such as creating a user, granting access packages, and disabling them at termination?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your organization wants to allow guests from a specific trusted partner tenant to bypass MFA in your tenant because they already satisfied MFA on their home tenant. Which Microsoft Entra setting enables this?$ms102r$, $ms102r$[{"id":"a","text":"Cross-tenant access settings — Inbound trust settings — Trust multifactor authentication from Microsoft Entra tenants"},{"id":"b","text":"A Conditional Access named location"},{"id":"c","text":"Per-user MFA for the partner organization"},{"id":"d","text":"A federation trust in Microsoft Entra Connect"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Cross-tenant access settings include inbound trust controls to accept MFA, device-compliance, and Entra-joined claims from a specific partner tenant. Named locations are network IP scopes; per-user MFA and Connect federation are different controls.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your organization wants to allow guests from a specific trusted partner tenant to bypass MFA in your tenant because they already satisfied MFA on their home tenant. Which Microsoft Entra setting enables this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user is reporting that legitimate quarantine releases are taking too long because there is no admin available. Which Defender for Office 365 feature lets users request release of their own quarantined messages?$ms102r$, $ms102r$[{"id":"a","text":"End-user spam notifications and self-service release in quarantine policy"},{"id":"b","text":"Anti-spam allow-list of the user's address"},{"id":"c","text":"A retention label applied to the quarantine"},{"id":"d","text":"A Power Automate flow only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Quarantine policies allow end-user request-to-release (or direct release, depending on type). End-user notifications and the quarantine portal expose this. Allow-listing the user does nothing for quarantined inbound; retention is unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/quarantine-about","label":"Microsoft Learn — Quarantined email messages in EOP and Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user is reporting that legitimate quarantine releases are taking too long because there is no admin available. Which Defender for Office 365 feature lets users request release of their own quarantined messages?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Defender XDR incident shows correlated alerts from email, endpoint, and identity. As an analyst, what is the BEST first action after opening the incident?$ms102r$, $ms102r$[{"id":"a","text":"Review the attack story / Graph view to understand the timeline and entities involved"},{"id":"b","text":"Immediately mark the incident as resolved to clear the queue"},{"id":"c","text":"Delete the related quarantine items without review"},{"id":"d","text":"Disable all Defender alerting"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The attack story / graph view in Defender XDR summarizes the timeline, entities, and evidence — the starting point for triage. Marking resolved prematurely, deleting evidence, or disabling alerting are anti-patterns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender-portal","label":"Microsoft Learn — The Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Defender XDR incident shows correlated alerts from email, endpoint, and identity. As an analyst, what is the BEST first action after opening the incident?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You authored a hunting query that returns suspicious behaviors. You want to operationalize it so it runs automatically and creates alerts. Which feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Custom detection rule built on the saved hunting query"},{"id":"b","text":"A Power Automate flow only"},{"id":"c","text":"A retention policy"},{"id":"d","text":"A DLP rule"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Custom detection rules promote a hunting query to scheduled detections that create alerts and incidents in Defender XDR. Power Automate alone, retention, and DLP do not produce SOC alerts.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/advanced-hunting-overview","label":"Microsoft Learn — Advanced hunting in Microsoft Defender XDR"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You authored a hunting query that returns suspicious behaviors. You want to operationalize it so it runs automatically and creates alerts. Which feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A small subset of devices remains unmanaged. You want Defender for Endpoint to discover them via network signals from managed devices on the same subnet. Which feature provides this?$ms102r$, $ms102r$[{"id":"a","text":"Device discovery in Microsoft Defender for Endpoint"},{"id":"b","text":"Vulnerability assessment baselines"},{"id":"c","text":"EDR in passive mode"},{"id":"d","text":"Microsoft Defender Antivirus controlled folder access"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Device discovery in MDE finds unmanaged endpoints visible to onboarded devices and surfaces them in inventory. The other features address vulnerability posture, EDR mode, and ransomware protections respectively.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A small subset of devices remains unmanaged. You want Defender for Endpoint to discover them via network signals from managed devices on the same subnet. Which feature provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Defender Vulnerability Management.$ms102r$, $ms102r$[{"id":"a","text":"It surfaces software vulnerabilities (CVEs) on onboarded devices."},{"id":"b","text":"It can recommend security configuration changes (e.g. Microsoft security baselines)."},{"id":"c","text":"It supports requesting remediation tasks in Microsoft Intune."},{"id":"d","text":"It rotates DNS records automatically."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$Vulnerability Management surfaces CVEs and security configuration recommendations, and integrates with Intune for remediation tasks. It does not manage DNS records.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-vulnerability-management/defender-vulnerability-management","label":"Microsoft Learn — Microsoft Defender Vulnerability Management"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Defender Vulnerability Management.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Defender for Endpoint Indicator-of-Compromise (IOC) needs to be applied tenant-wide to block a specific file hash from executing on all onboarded devices. Where do you configure this?$ms102r$, $ms102r$[{"id":"a","text":"Settings > Endpoints > Rules > Indicators in the Microsoft Defender portal"},{"id":"b","text":"A Conditional Access named location"},{"id":"c","text":"A Purview retention label"},{"id":"d","text":"A Microsoft 365 admin center user property"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$IOC indicators for files (hashes), IPs, URLs/domains, and certificates are configured under Settings > Endpoints > Rules > Indicators in the Defender portal and applied across onboarded devices. The other options are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Defender for Endpoint Indicator-of-Compromise (IOC) needs to be applied tenant-wide to block a specific file hash from executing on all onboarded devices. Where do you configure this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to ensure that even if a user explicitly extracts an attachment, the file is detonated in a sandbox first. Which Safe Attachments configuration is correct?$ms102r$, $ms102r$[{"id":"a","text":"Set the Safe Attachments policy action to \"Dynamic Delivery\" (body delivered, attachment delivered after scan) or \"Block\""},{"id":"b","text":"Disable EOP anti-malware"},{"id":"c","text":"Add the sender to an allow-list"},{"id":"d","text":"Configure SPF only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Safe Attachments offers Off / Monitor / Block / Dynamic Delivery / Replace. Dynamic Delivery and Block both ensure detonation before user access. Disabling AM or allow-listing weakens security; SPF doesn't inspect attachments.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-attachments-about","label":"Microsoft Learn — Safe Attachments in Microsoft Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to ensure that even if a user explicitly extracts an attachment, the file is detonated in a sandbox first. Which Safe Attachments configuration is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which feature in Defender for Office 365 protects users from malicious URLs even after delivery, by rewriting links and checking destination reputation at click-time?$ms102r$, $ms102r$[{"id":"a","text":"Safe Links"},{"id":"b","text":"Safe Attachments"},{"id":"c","text":"Anti-spam (connection filter)"},{"id":"d","text":"Outbound spam policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Safe Links rewrites and time-of-click-checks URLs in email, Teams, and Office apps. Safe Attachments inspects files. Connection filters and outbound spam policies are about IPs/outbound traffic.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-links-about","label":"Microsoft Learn — Safe Links in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which feature in Defender for Office 365 protects users from malicious URLs even after delivery, by rewriting links and checking destination reputation at click-time?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A CFO's name and look-alike domain are being used in phishing attempts. Which Defender for Office 365 anti-phishing setting is most relevant?$ms102r$, $ms102r$[{"id":"a","text":"Impersonation protection (user and domain) with mailbox-intelligence-based learning"},{"id":"b","text":"A retention policy on Exchange"},{"id":"c","text":"A device compliance policy in Intune"},{"id":"d","text":"A Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Anti-phishing impersonation protection detects user and domain impersonation and can leverage mailbox intelligence. Retention, Intune compliance, and named locations don't address impersonation.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/anti-phishing-policies-about","label":"Microsoft Learn — Anti-phishing policies in Microsoft 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A CFO's name and look-alike domain are being used in phishing attempts. Which Defender for Office 365 anti-phishing setting is most relevant?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want EOP to authenticate outbound mail with DKIM for fabrikam.com. Which step is required after enabling DKIM signing?$ms102r$, $ms102r$[{"id":"a","text":"Publish the two CNAME records (selector1, selector2) for fabrikam.com in your public DNS"},{"id":"b","text":"Add an A record for the DKIM signing server"},{"id":"c","text":"Add an SPF record only"},{"id":"d","text":"Create an MX record to a partner"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Exchange Online provides two CNAME selectors (selector1, selector2) that must be published in public DNS for the custom domain so receivers can validate DKIM signatures. SPF is also recommended but does not enable DKIM.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dkim-configure","label":"Microsoft Learn — Use DKIM to validate outbound email sent from your custom domain"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want EOP to authenticate outbound mail with DKIM for fabrikam.com. Which step is required after enabling DKIM signing?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to detect identity-based attacks against on-premises Active Directory (e.g. NTLM relay, account enumeration). Which deployment is required by Microsoft Defender for Identity?$ms102r$, $ms102r$[{"id":"a","text":"Install the Defender for Identity sensor on each domain controller and (optionally) AD FS / Entra Connect servers"},{"id":"b","text":"Install the Defender for Endpoint sensor on workstations only"},{"id":"c","text":"Configure Microsoft Defender for Cloud Apps"},{"id":"d","text":"Onboard the domain controllers to Microsoft Sentinel only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Defender for Identity sensors must be installed on domain controllers (and AD FS / Entra Connect when applicable) to read AD traffic and security events. MDE alone, MDCA alone, or Sentinel alone do not provide identity-attack detection on AD.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-for-identity/what-is","label":"Microsoft Learn — What is Microsoft Defender for Identity?"},{"url":"https://learn.microsoft.com/en-us/defender-for-identity/deploy/capacity-planning","label":"Microsoft Learn — Plan capacity for Microsoft Defender for Identity"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to detect identity-based attacks against on-premises Active Directory (e.g. NTLM relay, account enumeration). Which deployment is required by Microsoft Defender for Identity?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A new SaaS app appears in Defender for Cloud Apps Cloud Discovery with a low compliance score and high data-risk score. Your action is to block its use on managed devices. Which integration accomplishes this?$ms102r$, $ms102r$[{"id":"a","text":"Tag the app as Unsanctioned in Defender for Cloud Apps to integrate with MDE network protection and block access on managed Windows devices"},{"id":"b","text":"Add the app to Conditional Access as a cloud app to grant access"},{"id":"c","text":"Apply a retention policy on the app"},{"id":"d","text":"Set a DLP policy to retain the data"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Tagging an app Unsanctioned causes Defender for Endpoint network protection to block access on managed Windows endpoints. Adding to CA grants, not blocks. Retention and DLP don't block app traffic.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/set-up-cloud-discovery","label":"Microsoft Learn — Set up Cloud Discovery in Microsoft Defender for Cloud Apps"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A new SaaS app appears in Defender for Cloud Apps Cloud Discovery with a low compliance score and high data-risk score. Your action is to block its use on managed devices. Which integration accomplishes this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to receive alerts when a user downloads an unusually high volume of files from SharePoint Online in a short time. Which Defender for Cloud Apps policy should you create?$ms102r$, $ms102r$[{"id":"a","text":"An anomaly detection / activity policy (e.g. mass download)"},{"id":"b","text":"A Conditional Access policy with named location"},{"id":"c","text":"An EOP outbound spam policy"},{"id":"d","text":"A Safe Links policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Defender for Cloud Apps ships built-in anomaly detection (e.g. "Unusual file download") and supports custom activity policies. CA, EOP, and Safe Links don't monitor SharePoint download volume.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/control-cloud-apps-with-policies","label":"Microsoft Learn — Control cloud apps with policies"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to receive alerts when a user downloads an unusually high volume of files from SharePoint Online in a short time. Which Defender for Cloud Apps policy should you create?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Where in the Defender portal can an administrator review tenant-wide improvement actions ranked by impact on the security posture (with one-click links to remediation)?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Secure Score (Exposure management > Secure score)"},{"id":"b","text":"Audit search"},{"id":"c","text":"Mail flow rules"},{"id":"d","text":"Quarantine"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft Secure Score ranks improvement actions across identity, devices, apps, and data with links to remediate. Audit, mail-flow rules, and quarantine address different needs.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-secure-score","label":"Microsoft Learn — Microsoft Secure Score"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Where in the Defender portal can an administrator review tenant-wide improvement actions ranked by impact on the security posture (with one-click links to remediation)?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which mode of Microsoft Defender Antivirus allows a non-Microsoft AV product to be the primary AV, while Defender continues to provide EDR sensor data?$ms102r$, $ms102r$[{"id":"a","text":"Passive mode"},{"id":"b","text":"Active mode"},{"id":"c","text":"Block mode"},{"id":"d","text":"Tamper protection mode"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Passive mode lets a third-party AV be primary while Defender provides EDR telemetry. Active mode is the default primary AV mode. "Block mode" refers to EDR-in-block — a separate feature. Tamper protection is anti-tamper.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which mode of Microsoft Defender Antivirus allows a non-Microsoft AV product to be the primary AV, while Defender continues to provide EDR sensor data?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Automated investigation and response (AIR) in Defender XDR remediates without analyst approval if the automation level is set to which mode?$ms102r$, $ms102r$[{"id":"a","text":"Full automation (remediation actions executed automatically)"},{"id":"b","text":"Semi — wait for approval on any device"},{"id":"c","text":"No automated response"},{"id":"d","text":"Microsoft Sentinel-only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Full-automation mode executes recommended remediation without explicit analyst approval. Semi modes require approval on at least some actions. "No automated response" disables AIR. Sentinel is a separate SIEM product.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/automated-investigations","label":"Microsoft Learn — Automated investigation and response in Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Automated investigation and response (AIR) in Defender XDR remediates without analyst approval if the automation level is set to which mode?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Defender for Office 365 preset security policies.$ms102r$, $ms102r$[{"id":"a","text":"They apply Microsoft-recommended settings for EOP and Defender for Office 365 in a single click."},{"id":"b","text":"They include Standard and Strict tiers."},{"id":"c","text":"They override all custom policies and cannot coexist with them."},{"id":"d","text":"They take precedence over policies of lower priority but custom policies can still exist."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$Preset policies (Standard/Strict) ship Microsoft-recommended baselines and take precedence according to order of evaluation. They can coexist with custom policies in the same tenant.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/preset-security-policies","label":"Microsoft Learn — Preset security policies in EOP and Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Defender for Office 365 preset security policies.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A simulated phishing campaign is being planned to assess employee resilience. After users click, you want them to receive a short training module appropriate to the type of phishing. Which feature supports this?$ms102r$, $ms102r$[{"id":"a","text":"Attack simulation training with assigned training modules"},{"id":"b","text":"Microsoft Defender for Cloud Apps reports"},{"id":"c","text":"A retention label"},{"id":"d","text":"A communication compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Attack simulation training in Defender for Office 365 assigns training to users who interact with the simulation. The other features address different concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/attack-simulation-training-get-started","label":"Microsoft Learn — Get started using Attack simulation training"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A simulated phishing campaign is being planned to assess employee resilience. After users click, you want them to receive a short training module appropriate to the type of phishing. Which feature supports this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which set of records is required to fully authenticate outbound mail from a domain so that recipients can validate spoofing protections (alignment of From: domain)?$ms102r$, $ms102r$[{"id":"a","text":"SPF, DKIM, and DMARC"},{"id":"b","text":"A only"},{"id":"c","text":"NS only"},{"id":"d","text":"PTR only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$SPF lists authorized senders, DKIM signs messages, and DMARC ties the two to the visible From: address and sets policy. A/NS/PTR alone do not authenticate mail.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-spf-configure","label":"Microsoft Learn — Set up SPF to help prevent spoofing"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dkim-configure","label":"Microsoft Learn — Use DKIM to validate outbound email sent from your custom domain"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dmarc-configure","label":"Microsoft Learn — Use DMARC to validate email"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which set of records is required to fully authenticate outbound mail from a domain so that recipients can validate spoofing protections (alignment of From: domain)?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A high-severity alert says "Suspicious PowerShell command line" on a domain controller. Which Microsoft product likely generated this alert and where do you investigate?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Defender for Identity — investigate in the Defender portal alert + the DC sensor health page"},{"id":"b","text":"Microsoft Defender for Office 365 — investigate in Outlook"},{"id":"c","text":"Microsoft Purview Compliance Manager"},{"id":"d","text":"Microsoft Intune device compliance"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Suspicious PowerShell activity on a DC is a signature DefIdentity / MDE detection; investigation occurs in the Defender portal alert with sensor context. The other products do not detect on-DC PowerShell behavior.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-for-identity/what-is","label":"Microsoft Learn — What is Microsoft Defender for Identity?"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A high-severity alert says "Suspicious PowerShell command line" on a domain controller. Which Microsoft product likely generated this alert and where do you investigate?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Microsoft Security Exposure Management combines security posture, vulnerabilities, identities, and other signals into prioritized initiatives. Where is it found?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Defender portal under Exposure management"},{"id":"b","text":"Microsoft 365 admin center > Health"},{"id":"c","text":"Microsoft Entra > Identity Protection"},{"id":"d","text":"Microsoft Purview Audit"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Exposure Management is in the Defender portal under Exposure management. The other options surface different signals (admin-center health, Entra ID Protection, Purview Audit).$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/security-exposure-management/microsoft-security-exposure-management","label":"Microsoft Learn — Microsoft Security Exposure Management"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Microsoft Security Exposure Management combines security posture, vulnerabilities, identities, and other signals into prioritized initiatives. Where is it found?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A regulator requires that you protect documents containing personally identifiable information (PII) at rest and in transit. Which Microsoft Purview capability encrypts the document content and enforces who can decrypt it?$ms102r$, $ms102r$[{"id":"a","text":"Sensitivity labels with encryption enabled"},{"id":"b","text":"Retention labels"},{"id":"c","text":"DLP exceptions"},{"id":"d","text":"Auditing policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sensitivity labels apply encryption (Azure RMS / Purview Information Protection) and define who can read/modify the file. Retention labels manage lifecycle. DLP exceptions allow flows. Audit logs activities.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitivity-labels","label":"Microsoft Learn — Learn about sensitivity labels"},{"url":"https://learn.microsoft.com/en-us/purview/create-sensitivity-labels","label":"Microsoft Learn — Publish sensitivity labels by creating a label policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A regulator requires that you protect documents containing personally identifiable information (PII) at rest and in transit. Which Microsoft Purview capability encrypts the document content and enforces who can decrypt it?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Purview feature should an investigator use to scan and identify high-risk communications in Teams chats for harassment or threats, with reviewers redacting personal data?$ms102r$, $ms102r$[{"id":"a","text":"Communication compliance"},{"id":"b","text":"eDiscovery (Standard)"},{"id":"c","text":"Information Barriers"},{"id":"d","text":"Insider risk management"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Communication compliance scans Teams/Exchange/Yammer messages for inappropriate content with reviewers and pseudonymization. eDiscovery is for legal investigations. Information Barriers prevent communications. Insider risk monitors behavior, not message content review.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/communication-compliance","label":"Microsoft Learn — Learn about communication compliance"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Purview feature should an investigator use to scan and identify high-risk communications in Teams chats for harassment or threats, with reviewers redacting personal data?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Purview DLP policies.$ms102r$, $ms102r$[{"id":"a","text":"Policies can target Exchange Online, SharePoint Online, OneDrive for Business, Teams chats, and Windows/macOS endpoints."},{"id":"b","text":"Policies can use sensitive information types, sensitivity labels, or trainable classifiers as conditions."},{"id":"c","text":"Endpoint DLP can audit and block file activities such as USB copy and cloud upload."},{"id":"d","text":"DLP policies bypass auditing by default."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$DLP can target multiple workloads, leverages SITs/labels/trainable classifiers, and endpoint DLP can govern USB and cloud-upload actions. DLP activity is logged in the Audit log, not bypassed.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp","label":"Microsoft Learn — Data Loss Prevention overview"},{"url":"https://learn.microsoft.com/en-us/purview/endpoint-dlp-getting-started","label":"Microsoft Learn — Get started with Endpoint data loss prevention"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Purview DLP policies.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user copies a confidential file to a USB drive. You want the action blocked on managed Windows endpoints while still allowing copies between sanctioned cloud apps. Which feature provides this?$ms102r$, $ms102r$[{"id":"a","text":"Endpoint DLP with the \"Copy to USB removable media\" activity blocked and sanctioned-cloud apps allowed"},{"id":"b","text":"A retention policy on the document library"},{"id":"c","text":"A communication compliance review"},{"id":"d","text":"Entra Conditional Access named locations"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Endpoint DLP governs activities like "Copy to USB" and supports allow-lists for sanctioned cloud apps/printers. Retention, communication compliance, and named locations address other concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/endpoint-dlp-getting-started","label":"Microsoft Learn — Get started with Endpoint data loss prevention"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp","label":"Microsoft Learn — Data Loss Prevention overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user copies a confidential file to a USB drive. You want the action blocked on managed Windows endpoints while still allowing copies between sanctioned cloud apps. Which feature provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your organization plans to migrate to records management for declaring official corporate records. Which Purview feature should you use to declare items as records, restrict their modification, and apply file-plan metadata?$ms102r$, $ms102r$[{"id":"a","text":"Retention labels with the \"Mark items as records\" option, published via a file plan"},{"id":"b","text":"Sensitivity labels with encryption"},{"id":"c","text":"Communication compliance policies"},{"id":"d","text":"Defender for Cloud Apps policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Records management uses retention labels that declare items as records or regulatory records, with file-plan metadata. Sensitivity labels protect content but do not declare records. Communication compliance and Defender for Cloud Apps are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/file-plan-manager","label":"Microsoft Learn — Create retention labels and apply them in apps"},{"url":"https://learn.microsoft.com/en-us/purview/retention","label":"Microsoft Learn — Learn about retention policies and retention labels"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your organization plans to migrate to records management for declaring official corporate records. Which Purview feature should you use to declare items as records, restrict their modification, and apply file-plan metadata?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A legal team needs to collect documents from SharePoint, OneDrive, and Exchange that contain the term "Project Atlas" for an investigation. Which Purview tool should they use to scope, search, and export the content?$ms102r$, $ms102r$[{"id":"a","text":"eDiscovery (Premium) case"},{"id":"b","text":"Content explorer"},{"id":"c","text":"Activity explorer"},{"id":"d","text":"Compliance Manager"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$eDiscovery (Premium) supports case management, advanced collection, review sets, analytics, and export — the full investigation workflow. Content/Activity explorers are for posture, not investigations. Compliance Manager is a scoring tool.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/ediscovery-overview","label":"Microsoft Learn — Overview of eDiscovery (Premium)"},{"url":"https://learn.microsoft.com/en-us/purview/ediscovery","label":"Microsoft Learn — Microsoft Purview eDiscovery solutions"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A legal team needs to collect documents from SharePoint, OneDrive, and Exchange that contain the term "Project Atlas" for an investigation. Which Purview tool should they use to scope, search, and export the content?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want a sensitivity label to grant Read-only permission to all employees but allow co-authoring for the Finance team. Which capability of sensitivity labels provides this?$ms102r$, $ms102r$[{"id":"a","text":"Encryption permissions configured per user/group"},{"id":"b","text":"A retention period setting"},{"id":"c","text":"Endpoint DLP rules"},{"id":"d","text":"A Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sensitivity-label encryption supports assigning permissions (Co-Author, Reviewer, Viewer, etc.) per user or group. Retention is lifecycle. Endpoint DLP governs activities. CA is sign-in conditioning.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitivity-labels","label":"Microsoft Learn — Learn about sensitivity labels"},{"url":"https://learn.microsoft.com/en-us/purview/create-sensitivity-labels","label":"Microsoft Learn — Publish sensitivity labels by creating a label policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want a sensitivity label to grant Read-only permission to all employees but allow co-authoring for the Finance team. Which capability of sensitivity labels provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to integrate HR signals so that data-exfiltration risk scoring increases for employees who have submitted a resignation. Which Microsoft Purview feature uses HR connectors?$ms102r$, $ms102r$[{"id":"a","text":"Insider risk management (using HR data connector)"},{"id":"b","text":"eDiscovery (Standard)"},{"id":"c","text":"Compliance Manager assessments"},{"id":"d","text":"Audit search"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Insider risk management consumes HR signals through a data connector (resignation date, termination date, level) to enrich risk scoring. The other features don't take HR feeds.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/insider-risk-management","label":"Microsoft Learn — Learn about insider risk management"},{"url":"https://learn.microsoft.com/en-us/purview/insider-risk-management-policies","label":"Microsoft Learn — Insider risk management policies"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p2$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to integrate HR signals so that data-exfiltration risk scoring increases for employees who have submitted a resignation. Which Microsoft Purview feature uses HR connectors?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to add the second custom domain northwind.com to a tenant that already hosts contoso.com. Which statement about multi-domain Microsoft 365 tenants is correct?$ms102r$, $ms102r$[{"id":"a","text":"A single tenant can host multiple verified custom domains, and any verified domain can be set as the user's primary SMTP suffix"},{"id":"b","text":"Only one custom domain is supported per tenant"},{"id":"c","text":"You must create a separate tenant for each domain"},{"id":"d","text":"Domain verification can be skipped if MX is configured first"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Tenants support multiple verified custom domains, and per-user UPN/primary-SMTP can use any of them. You don't need a tenant per domain. Verification is required before mail flow can be configured.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/setup/add-domain","label":"Microsoft Learn — Add a domain to Microsoft 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to add the second custom domain northwind.com to a tenant that already hosts contoso.com. Which statement about multi-domain Microsoft 365 tenants is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A regional IT team should be able to manage all settings of users located in the Singapore administrative unit, including unit-restricted password reset, but only within Singapore. Which role and scope are correct?$ms102r$, $ms102r$[{"id":"a","text":"Assign the User Administrator role at the Singapore administrative unit scope"},{"id":"b","text":"Assign Global Administrator with no scope"},{"id":"c","text":"Assign Reports Reader at the tenant scope"},{"id":"d","text":"Assign Authentication Administrator at the tenant scope"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Administrative-unit-scoped User Administrator restricts user-management actions to the unit. Global Administrator is unscoped; Reports Reader is read-only; tenant-wide Authentication Administrator exceeds scope.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/administrative-units","label":"Microsoft Learn — Administrative units in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A regional IT team should be able to manage all settings of users located in the Singapore administrative unit, including unit-restricted password reset, but only within Singapore. Which role and scope are correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You purchased Microsoft 365 E5 licenses for 200 users. Which is the MOST efficient way to assign licenses to all 200 at once?$ms102r$, $ms102r$[{"id":"a","text":"Group-based licensing on a Microsoft Entra security group containing the 200 users"},{"id":"b","text":"Per-user assignment through PowerShell one user at a time"},{"id":"c","text":"A device compliance policy"},{"id":"d","text":"A Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Group-based licensing scales bulk assignment with simple membership management. Per-user PowerShell is feasible but error-prone. Compliance policies and named locations have nothing to do with licensing.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/users/licensing-groups-assign","label":"Microsoft Learn — Group-based licensing in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You purchased Microsoft 365 E5 licenses for 200 users. Which is the MOST efficient way to assign licenses to all 200 at once?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to receive critical Message center posts directly in Outlook (via the Microsoft 365 admin app or email). Which configuration enables this?$ms102r$, $ms102r$[{"id":"a","text":"Configure Message center preferences > email notifications and select the desired services"},{"id":"b","text":"Enable inbox rules for an internal mailbox"},{"id":"c","text":"Configure a retention label"},{"id":"d","text":"Disable Service health"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Message center preferences let you choose who receives email digests of posts and which services to include. Inbox rules don't generate Message center notifications.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/manage/message-center","label":"Microsoft Learn — Stay on top of changes with Message center"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to receive critical Message center posts directly in Outlook (via the Microsoft 365 admin app or email). Which configuration enables this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft 365 Apps for enterprise deployments.$ms102r$, $ms102r$[{"id":"a","text":"The Office Deployment Tool (ODT) uses an XML configuration to install specific products, languages, and update channels."},{"id":"b","text":"Microsoft 365 Apps admin center can author configuration XML and assign deployment groups."},{"id":"c","text":"Microsoft 365 Apps installs are not affected by the chosen update channel after install."},{"id":"d","text":"A serviceing profile can pin a specific build to a deployment ring."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$ODT + XML, the Apps admin center, and servicing profiles are all standard tools. The chosen update channel determines ongoing update behavior — it absolutely affects post-install servicing.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/deployoffice/deployment-guide-microsoft-365-apps","label":"Microsoft Learn — Deployment guide for Microsoft 365 Apps"},{"url":"https://learn.microsoft.com/en-us/deployoffice/overview-update-channels","label":"Microsoft Learn — Overview of update channels for Microsoft 365 Apps"},{"url":"https://learn.microsoft.com/en-us/deployoffice/admincenter/overview","label":"Microsoft Learn — Overview of the Microsoft 365 Apps admin center"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft 365 Apps for enterprise deployments.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to onboard 1,000 Windows 11 devices via Autopilot but pre-stage the OS image and apps with an IT technician so end users receive a near-ready device when they sign in. Which Autopilot mode meets this?$ms102r$, $ms102r$[{"id":"a","text":"Pre-provisioning (formerly white glove)"},{"id":"b","text":"User-driven mode without pre-provisioning"},{"id":"c","text":"Self-deploying mode"},{"id":"d","text":"Existing devices reset"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Pre-provisioning lets IT pre-stage OS/apps/policies, so end-user sign-in is fast. User-driven without pre-provisioning leaves all setup until user sign-in. Self-deploying has no user. Reset targets enrolled devices.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/autopilot/windows-autopilot","label":"Microsoft Learn — Windows Autopilot overview"},{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to onboard 1,000 Windows 11 devices via Autopilot but pre-stage the OS image and apps with an IT technician so end users receive a near-ready device when they sign in. Which Autopilot mode meets this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$When configuring Intune to be the MDM authority for Windows auto-enrollment of Entra-joined devices, which two licensing conditions must be met?$ms102r$, $ms102r$[{"id":"a","text":"Users must hold a license that includes Intune, and the MDM/MAM user scope under Entra ID > Mobility must include them"},{"id":"b","text":"Users must be guests (B2B)"},{"id":"c","text":"Users must be assigned a Power BI Pro license"},{"id":"d","text":"Devices must be domain-joined to a partner tenant"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Auto-enrollment requires users to be in the Mobility MDM user scope and to be licensed for Intune. Guest users, Power BI, and partner-tenant domain join are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/device-enrollment","label":"Microsoft Learn — Device enrollment in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$When configuring Intune to be the MDM authority for Windows auto-enrollment of Entra-joined devices, which two licensing conditions must be met?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to require devices to be marked compliant before they can access Exchange Online and SharePoint Online. Where do you enforce this?$ms102r$, $ms102r$[{"id":"a","text":"A Conditional Access policy with the grant control \"Require device to be marked as compliant\""},{"id":"b","text":"A retention policy"},{"id":"c","text":"A DLP policy"},{"id":"d","text":"A communication compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$CA enforces device-compliance requirements as a grant control. Retention, DLP, and communication compliance address content concerns, not access conditions.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/device-compliance-get-started","label":"Microsoft Learn — Use device compliance policies in Intune"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to require devices to be marked compliant before they can access Exchange Online and SharePoint Online. Where do you enforce this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Some of your tenant's users routinely need administrative actions that exceed a delegated User Administrator. To grant just-in-time access, scoped to a single task, with approval and break-glass review, you should configure ____.$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra Privileged Identity Management (PIM) with approval-required activation"},{"id":"b","text":"Per-user MFA"},{"id":"c","text":"Group-based licensing"},{"id":"d","text":"Insider risk management"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$PIM is the canonical Entra solution for just-in-time, scoped, approval-required role activation with audit. The other options solve different problems.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Some of your tenant's users routinely need administrative actions that exceed a delegated User Administrator. To grant just-in-time access, scoped to a single task, with approval and break-glass review, you should configure ____.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A new partner needs read-only access to a single SharePoint site without becoming a Global Reader. Which approach satisfies least privilege?$ms102r$, $ms102r$[{"id":"a","text":"Invite the partner as a Microsoft Entra B2B guest and grant SharePoint site permissions only"},{"id":"b","text":"Grant Global Reader to the partner"},{"id":"c","text":"Add the partner as a domain administrator on-premises"},{"id":"d","text":"Create a service principal"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$B2B guest + site-only SharePoint permissions is the minimal grant. Global Reader is tenant-wide read. On-prem admin and service principals address different scenarios.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A new partner needs read-only access to a single SharePoint site without becoming a Global Reader. Which approach satisfies least privilege?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your Microsoft 365 tenant has 50 users with the Global Administrator role. Microsoft recommends what for production hygiene?$ms102r$, $ms102r$[{"id":"a","text":"Limit Global Administrators to fewer than 5 active accounts plus at least 2 break-glass accounts; use PIM eligibility for additional administrators"},{"id":"b","text":"Add every Active Directory user as a Global Administrator"},{"id":"c","text":"Disable MFA on all Global Administrators"},{"id":"d","text":"Remove all admin roles entirely"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft recommends keeping Global Administrator counts very low, using PIM eligibility for others, and having 2+ emergency-access accounts. The other options violate basic security guidance.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"},{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your Microsoft 365 tenant has 50 users with the Global Administrator role. Microsoft recommends what for production hygiene?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A specific employee's onmicrosoft.com account must be temporarily blocked because they are on extended leave, but their mailbox needs to remain intact for delegated access. Which action(s) should you take?$ms102r$, $ms102r$[{"id":"a","text":"Block sign-in on the user (Sign-in blocked) while keeping the mailbox license assigned"},{"id":"b","text":"Delete the user"},{"id":"c","text":"Remove their license and delete the mailbox"},{"id":"d","text":"Make the account a Global Administrator"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Blocking sign-in prevents access while preserving mailbox/licensing. Deleting the user removes the mailbox. Removing the license starts a retention timer. Making them a Global Admin is the opposite of the goal.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-create-delete-users","label":"Microsoft Learn — How to add or delete users in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A specific employee's onmicrosoft.com account must be temporarily blocked because they are on extended leave, but their mailbox needs to remain intact for delegated access. Which action(s) should you take?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A reseller manages 30 SMB tenants and wants to apply a baseline policy (security defaults, MFA) consistently across them. Which Microsoft 365 service provides multi-tenant baseline configurations to partners?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft 365 Lighthouse"},{"id":"b","text":"Microsoft Entra Connect Health"},{"id":"c","text":"Microsoft Sentinel"},{"id":"d","text":"Microsoft Defender for Cloud"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Lighthouse provides multi-tenant baseline configuration and posture management for partners managing SMB tenants. The others are not multi-tenant management.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/lighthouse/m365-lighthouse-overview","label":"Microsoft Learn — Multi-tenant management with Microsoft 365 Lighthouse"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A reseller manages 30 SMB tenants and wants to apply a baseline policy (security defaults, MFA) consistently across them. Which Microsoft 365 service provides multi-tenant baseline configurations to partners?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You've assigned the SharePoint Administrator role to a user. Which Microsoft 365 admin centers can they manage by default?$ms102r$, $ms102r$[{"id":"a","text":"The SharePoint admin center, and they have access to view related Microsoft 365 admin center info, but cannot manage Exchange or Teams unless granted additional roles"},{"id":"b","text":"All admin centers"},{"id":"c","text":"Only the Microsoft 365 admin center home page"},{"id":"d","text":"Only the Defender portal"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$SharePoint Administrator manages SharePoint and OneDrive workloads. Cross-workload management requires additional role grants. Other answers misstate the scope.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You've assigned the SharePoint Administrator role to a user. Which Microsoft 365 admin centers can they manage by default?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to track who, when, and what was changed in tenant administration (license assignment, role grants). Where in Microsoft 365 should you look?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Purview Audit log search"},{"id":"b","text":"Service health"},{"id":"c","text":"Quarantine"},{"id":"d","text":"Defender for Cloud Apps file policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Purview Audit captures admin actions across the tenant. Service health shows incidents; quarantine is mail; file policies are SaaS content controls.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/audit-search","label":"Microsoft Learn — Search the audit log in the Microsoft Purview portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to track who, when, and what was changed in tenant administration (license assignment, role grants). Where in Microsoft 365 should you look?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You need to give all developers access to Microsoft 365 admin center > Marketplace to install integration apps, but not to manage anything else. Which approach is correct?$ms102r$, $ms102r$[{"id":"a","text":"Assign the appropriate granular role (e.g. Cloud Application Administrator) only to developers needing the capability"},{"id":"b","text":"Make every developer a Global Administrator"},{"id":"c","text":"Block sign-ins for developers"},{"id":"d","text":"Apply a retention policy to developers"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Use a granular role like Cloud Application Administrator (or Application Administrator) per least-privilege. Global Administrator is excessive; blocking and retention don't address the requirement.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"},{"url":"https://learn.microsoft.com/en-us/microsoft-365/admin/add-users/about-admin-roles","label":"Microsoft Learn — About admin roles in the Microsoft 365 admin center"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You need to give all developers access to Microsoft 365 admin center > Marketplace to install integration apps, but not to manage anything else. Which approach is correct?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Intune feature lets you target the same configuration profile to two different platforms (Windows and macOS) at once if the settings happen to overlap?$ms102r$, $ms102r$[{"id":"a","text":"Settings catalog (profile templates per platform — you configure one profile per platform but can copy settings between)"},{"id":"b","text":"A single multi-platform profile that applies to every OS"},{"id":"c","text":"A retention policy"},{"id":"d","text":"A Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Intune profiles are per platform; the Settings catalog supports rich per-platform configuration and you typically create a profile per platform. There is no single multi-OS configuration profile.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/mem/intune/configuration/device-profiles","label":"Microsoft Learn — Apply features and settings on devices with Intune configuration profiles"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/what-is-intune","label":"Microsoft Learn — What is Microsoft Intune?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Intune feature lets you target the same configuration profile to two different platforms (Windows and macOS) at once if the settings happen to overlap?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Deploy and manage a Microsoft 365 tenant$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Entra Cloud Sync versus Microsoft Entra Connect Sync.$ms102r$, $ms102r$[{"id":"a","text":"Cloud Sync uses lightweight agents that communicate outbound to Entra ID."},{"id":"b","text":"Cloud Sync is best for multiple disconnected forests and simpler deployments."},{"id":"c","text":"Entra Connect Sync supports more advanced sync scenarios such as device write-back and group write-back."},{"id":"d","text":"Both Cloud Sync and Entra Connect Sync require ADFS to function."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$Cloud Sync uses outbound-only agents and is best for simpler/multi-forest scenarios; Connect Sync supports advanced scenarios. Neither requires ADFS — federation is a separate, optional authentication choice.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/cloud-sync/what-is-cloud-sync","label":"Microsoft Learn — What is Microsoft Entra Cloud Sync?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sync-whatis","label":"Microsoft Learn — Microsoft Entra Connect Sync: Understand and customize synchronization"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-fed","label":"Microsoft Learn — Federation with AD FS and Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Entra Cloud Sync versus Microsoft Entra Connect Sync.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You created a Conditional Access policy in "Report-only" mode targeting all users. After 48 hours of insights, you want to start enforcing it. Which step is required?$ms102r$, $ms102r$[{"id":"a","text":"Change the policy state from Report-only to On"},{"id":"b","text":"Delete and recreate the policy"},{"id":"c","text":"Add the policy to a retention label"},{"id":"d","text":"Re-register all devices"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Setting the policy state to "On" enforces it. Report-only logs what would have happened. Deleting and recreating is unnecessary. Retention and re-registration are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-conditional-access-policies","label":"Microsoft Learn — Build a Conditional Access policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You created a Conditional Access policy in "Report-only" mode targeting all users. After 48 hours of insights, you want to start enforcing it. Which step is required?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You suspect that a previously synchronized on-premises user is no longer being updated to Entra ID. What is the FIRST place to check the synchronization state?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra Connect Health (or Entra Connect agent / portal) for sync errors and last sync timestamp"},{"id":"b","text":"Microsoft Defender XDR incidents"},{"id":"c","text":"Microsoft Purview Audit"},{"id":"d","text":"Conditional Access insights"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Entra Connect Health (or the Entra ID > Microsoft Entra Connect blade) surfaces sync agent health, latest sync timestamps, and per-object errors. The others address security incidents, audit, and CA policy results.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-azure-ad-connect","label":"Microsoft Learn — What is Microsoft Entra Connect?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sync-whatis","label":"Microsoft Learn — Microsoft Entra Connect Sync: Understand and customize synchronization"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You suspect that a previously synchronized on-premises user is no longer being updated to Entra ID. What is the FIRST place to check the synchronization state?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Conditional Access grant control offers the FASTEST sign-in experience while still enforcing MFA for users who already authenticated with phishing-resistant methods?$ms102r$, $ms102r$[{"id":"a","text":"Authentication Strengths — Phishing-resistant MFA"},{"id":"b","text":"Per-user MFA"},{"id":"c","text":"Security defaults"},{"id":"d","text":"Sign-in frequency = always"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Authentication strengths can require phishing-resistant MFA (FIDO2, Windows Hello, certificate-based) — fastest in practice. Per-user MFA prompts always. Security defaults are broad. Sign-in frequency=always forces frequent re-prompts.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-passwordless","label":"Microsoft Learn — Passwordless authentication options for Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Conditional Access grant control offers the FASTEST sign-in experience while still enforcing MFA for users who already authenticated with phishing-resistant methods?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Entra group types.$ms102r$, $ms102r$[{"id":"a","text":"Security groups can have assigned or dynamic membership."},{"id":"b","text":"Microsoft 365 groups create a shared mailbox, calendar, SharePoint site, and Teams team."},{"id":"c","text":"Distribution groups can be used for Conditional Access targeting."},{"id":"d","text":"A group can host nested group assignments depending on type."}]$ms102r$::jsonb, $ms102r$["a","b"]$ms102r$::jsonb, $ms102r$Security groups support both membership models; M365 groups provision shared resources. Distribution groups cannot be CA targets (CA targets security groups and M365 groups). Nesting is limited and not universally supported.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-manage-groups","label":"Microsoft Learn — Manage groups in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/users/groups-dynamic-membership","label":"Microsoft Learn — Dynamic membership rules for groups"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Entra group types.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user travels to a country where the company has never had an employee. Sign-ins from there should be blocked unless approved. Which Conditional Access condition should you use?$ms102r$, $ms102r$[{"id":"a","text":"Locations condition with the country added to a \"Blocked countries\" named location"},{"id":"b","text":"Device platform = Windows"},{"id":"c","text":"Risk = none"},{"id":"d","text":"Application = Microsoft Teams"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Named locations support country/region and can be combined with a Block grant control. Device platform, risk, and a single application don't represent geography.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/location-condition","label":"Microsoft Learn — Named locations in Conditional Access"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user travels to a country where the company has never had an employee. Sign-ins from there should be blocked unless approved. Which Conditional Access condition should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to prevent users from registering for SSPR with security questions, while keeping authenticator-app and SMS as registration options. Where do you configure this?$ms102r$, $ms102r$[{"id":"a","text":"Authentication methods policy in Microsoft Entra ID"},{"id":"b","text":"A retention policy in Purview"},{"id":"c","text":"A Defender for Endpoint policy"},{"id":"d","text":"A communication compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Authentication methods policy enables/disables registration methods. The other features are unrelated to authentication-method registration.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-sspr-howitworks","label":"Microsoft Learn — How it works: Microsoft Entra self-service password reset"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to prevent users from registering for SSPR with security questions, while keeping authenticator-app and SMS as registration options. Where do you configure this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft Entra ID Protection report shows users currently at risk and the recommended remediation (e.g. confirm safe, force password change)?$ms102r$, $ms102r$[{"id":"a","text":"Risky users report"},{"id":"b","text":"Sign-in logs in Microsoft 365 admin center"},{"id":"c","text":"Conditional Access insights only"},{"id":"d","text":"Audit log in Purview"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The Risky users report enumerates risky users with risk state and recommended actions. Sign-in logs, CA insights, and Purview Audit don't consolidate user risk this way.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft Entra ID Protection report shows users currently at risk and the recommended remediation (e.g. confirm safe, force password change)?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A consultant needs admin rights for one specific Azure subscription, but should have no permissions in Microsoft 365 or Entra ID. Which best matches their need?$ms102r$, $ms102r$[{"id":"a","text":"Azure RBAC role (e.g. Contributor) on that subscription only — no Entra role assigned"},{"id":"b","text":"Global Administrator in Entra ID"},{"id":"c","text":"Microsoft Entra Application Administrator"},{"id":"d","text":"Microsoft 365 Service Administrator"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Azure resource roles (RBAC) are independent of Entra ID directory roles. Assigning Contributor at the subscription gives them what they need without Entra rights. The other options grant rights they don't need.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"},{"url":"https://learn.microsoft.com/en-us/entra/id-governance/privileged-identity-management/pim-configure","label":"Microsoft Learn — What is Microsoft Entra Privileged Identity Management?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A consultant needs admin rights for one specific Azure subscription, but should have no permissions in Microsoft 365 or Entra ID. Which best matches their need?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which feature lets an administrator decide who can invite external guests to the Microsoft Entra tenant?$ms102r$, $ms102r$[{"id":"a","text":"External collaboration settings in Microsoft Entra (Guest invite settings)"},{"id":"b","text":"A retention policy"},{"id":"c","text":"Tenant access policies"},{"id":"d","text":"Microsoft Entra Connect Health alerts"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$External collaboration settings define who can invite guests. The other options either do not exist (tenant access policies) or address different concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which feature lets an administrator decide who can invite external guests to the Microsoft Entra tenant?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to allow a Microsoft Authenticator passwordless sign-in for users who only have iOS devices. Which authentication method policy must be enabled?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Authenticator (passwordless sign-in) under Authentication methods policy"},{"id":"b","text":"OATH hardware tokens only"},{"id":"c","text":"Security questions only"},{"id":"d","text":"Phone number sign-in by SMS"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$The Microsoft Authenticator passwordless option must be enabled and scoped to the user group in the Authentication methods policy. SMS, OATH tokens, and security questions are different methods.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-passwordless","label":"Microsoft Learn — Passwordless authentication options for Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-authentication-methods","label":"Microsoft Learn — Authentication methods in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to allow a Microsoft Authenticator passwordless sign-in for users who only have iOS devices. Which authentication method policy must be enabled?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want managers to be able to grant temporary access packages (containing Teams + SharePoint + group memberships) to contractors with an automated approval workflow. Which Microsoft Entra feature should you use?$ms102r$, $ms102r$[{"id":"a","text":"Entitlement management access packages"},{"id":"b","text":"Conditional Access"},{"id":"c","text":"Microsoft Defender for Cloud Apps"},{"id":"d","text":"Self-service password reset"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Entitlement management bundles resources into access packages with approval workflows and time-bound assignments. CA gates sign-ins, MDCA governs SaaS, SSPR resets passwords.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/entitlement-management-overview","label":"Microsoft Learn — What is entitlement management?"},{"url":"https://learn.microsoft.com/en-us/entra/id-governance/access-reviews-overview","label":"Microsoft Learn — What are access reviews?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want managers to be able to grant temporary access packages (containing Teams + SharePoint + group memberships) to contractors with an automated approval workflow. Which Microsoft Entra feature should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to ensure that on-premises AD service accounts cannot be used to sign in to cloud apps even if synchronized. Which is the most appropriate approach?$ms102r$, $ms102r$[{"id":"a","text":"Use the cloudFiltered attribute to exclude the service-account OU or specific accounts from synchronization to Entra ID"},{"id":"b","text":"Assign them all the Global Administrator role"},{"id":"c","text":"Apply a sensitivity label to the accounts"},{"id":"d","text":"Add them to Conditional Access as targets and block them — but this still allows sign-in attempts"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Filtering OUs / specific accounts from sync ensures they don't exist in Entra ID. Blocking via CA is reactive; granting Global Admin is the opposite of the goal; sensitivity labels are for content protection.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-azure-ad-connect","label":"Microsoft Learn — What is Microsoft Entra Connect?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sync-whatis","label":"Microsoft Learn — Microsoft Entra Connect Sync: Understand and customize synchronization"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to ensure that on-premises AD service accounts cannot be used to sign in to cloud apps even if synchronized. Which is the most appropriate approach?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want every external Microsoft Entra B2B guest to be reviewed for continued business need every 90 days, with the inviter (sponsor) as the reviewer. Which feature satisfies the requirement?$ms102r$, $ms102r$[{"id":"a","text":"A recurring access review on Guest users with reviewer = \"user's manager or sponsor\""},{"id":"b","text":"A Conditional Access policy with sign-in frequency = 90 days"},{"id":"c","text":"Microsoft Entra B2B direct connect"},{"id":"d","text":"A retention label on guest user objects"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Access reviews can specifically target guest users and use the sponsor or manager as the reviewer on a recurring schedule. CA sign-in frequency forces a re-prompt but does not review need; B2B direct connect is a Teams feature; retention labels target content.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-governance/access-reviews-overview","label":"Microsoft Learn — What are access reviews?"},{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want every external Microsoft Entra B2B guest to be reviewed for continued business need every 90 days, with the inviter (sponsor) as the reviewer. Which feature satisfies the requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$In Microsoft Entra, you want non-admin end users to be prevented from consenting to third-party OAuth apps that request high-risk Microsoft Graph permissions, while still allowing a security admin to approve them. Which configuration enforces this?$ms102r$, $ms102r$[{"id":"a","text":"User consent settings = \"Do not allow user consent\" combined with an admin consent request workflow"},{"id":"b","text":"Block sign-ins for non-admins"},{"id":"c","text":"Disable Conditional Access"},{"id":"d","text":"Add all third-party apps to a Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$User consent settings can disable user consent entirely (or limit it to verified publishers/low-risk perms); admin consent workflow lets users request approval. Blocking sign-ins is excessive; CA named locations are network IP scopes.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/permissions-reference","label":"Microsoft Learn — Microsoft Entra built-in roles"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$In Microsoft Entra, you want non-admin end users to be prevented from consenting to third-party OAuth apps that request high-risk Microsoft Graph permissions, while still allowing a security admin to approve them. Which configuration enforces this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports their Microsoft Entra account was locked after a series of bad passwords. The IT team wants to confirm this was a real lockout and not a sign-in failure. Where should they investigate?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Entra > Monitoring > Sign-in logs (filter on the user and check the error code, e.g. AADSTS50053 / smart lockout)"},{"id":"b","text":"Microsoft 365 admin center > Reports > Usage"},{"id":"c","text":"A Conditional Access named location"},{"id":"d","text":"Defender for Office 365 quarantine"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Entra sign-in logs include status codes and errors that distinguish bad password from smart-lockout (e.g. AADSTS50053). Usage reports, named locations, and MDO quarantine do not surface auth-error details.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports their Microsoft Entra account was locked after a series of bad passwords. The IT team wants to confirm this was a real lockout and not a sign-in failure. Where should they investigate?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft Entra ID Protection setting governs the minimum risk level at which a sign-in is automatically blocked or required to reauthenticate, and what licensing is required to use these risk-based Conditional Access policies?$ms102r$, $ms102r$[{"id":"a","text":"The sign-in risk and user risk policies expose thresholds (low/medium/high) and require Microsoft Entra ID P2 licensing per affected user"},{"id":"b","text":"Per-user MFA controls the threshold, and licensing is included with all Microsoft 365 tenants"},{"id":"c","text":"Security defaults expose risk thresholds for free"},{"id":"d","text":"A retention policy controls the threshold"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Risk-based CA uses ID Protection signal at low/medium/high thresholds and requires Entra ID P2 licensing per affected user. Per-user MFA, security defaults, and retention policies do not expose risk thresholds.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/id-protection/overview-identity-protection","label":"Microsoft Learn — What is Microsoft Entra ID Protection?"},{"url":"https://learn.microsoft.com/en-us/entra/id-protection/concept-identity-protection-policies","label":"Microsoft Learn — Risk policies in Microsoft Entra ID Protection"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft Entra ID Protection setting governs the minimum risk level at which a sign-in is automatically blocked or required to reauthenticate, and what licensing is required to use these risk-based Conditional Access policies?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want a Microsoft Entra group whose membership is automatically populated from on-premises Active Directory through Microsoft Entra Connect Sync. Where is the source-of-authority for membership in this scenario?$ms102r$, $ms102r$[{"id":"a","text":"On-premises Active Directory — membership changes occur there and sync to Entra ID; you cannot edit the synced group's membership directly in Entra ID"},{"id":"b","text":"Microsoft Entra ID — changes happen there and write back to AD via Entra Connect"},{"id":"c","text":"Microsoft Intune device groups"},{"id":"d","text":"Microsoft 365 admin center Groups blade"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$For groups synced via Entra Connect Sync, on-premises AD is the source of authority for membership. Group write-back is supported only in limited scenarios. Intune device groups and the admin-center Groups blade do not own synced-group membership.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/whatis-azure-ad-connect","label":"Microsoft Learn — What is Microsoft Entra Connect?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/hybrid/connect/how-to-connect-sync-whatis","label":"Microsoft Learn — Microsoft Entra Connect Sync: Understand and customize synchronization"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-manage-groups","label":"Microsoft Learn — Manage groups in Microsoft Entra ID"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want a Microsoft Entra group whose membership is automatically populated from on-premises Active Directory through Microsoft Entra Connect Sync. Where is the source-of-authority for membership in this scenario?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Implement and manage Microsoft Entra identity and access$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your security team wants a Conditional Access policy to be deployed but only to a small pilot user group while the rest of the tenant continues unaffected. Which targeting approach is recommended?$ms102r$, $ms102r$[{"id":"a","text":"Set the policy to \"On\" but scope Users and groups = Include = the pilot security group, Exclude = break-glass accounts"},{"id":"b","text":"Apply the policy in Report-only mode to all users indefinitely"},{"id":"c","text":"Set the policy to Off and ask the pilot users to sign in manually"},{"id":"d","text":"Disable Microsoft Entra ID for non-pilot users"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Including only the pilot group (and excluding break-glass accounts) is the recommended controlled rollout pattern. Report-only never enforces; Off does nothing; disabling Entra ID is destructive.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/concept-conditional-access-policies","label":"Microsoft Learn — Build a Conditional Access policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your security team wants a Conditional Access policy to be deployed but only to a small pilot user group while the rest of the tenant continues unaffected. Which targeting approach is recommended?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$An analyst is reviewing an Incident in Defender XDR. They want to take a containment action like isolating a device, stopping a process, or disabling a user account directly from the incident page. Which capability provides this?$ms102r$, $ms102r$[{"id":"a","text":"Response actions (live response and one-click remediation) integrated into the incident page"},{"id":"b","text":"Mail flow rules"},{"id":"c","text":"Retention policies"},{"id":"d","text":"Group-based licensing"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Response actions and live response are exposed from incident and entity pages in the Defender portal. Mail flow, retention, and licensing are not response controls for endpoints/identities.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender","label":"Microsoft Learn — Microsoft Defender XDR overview"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/incidents-overview","label":"Microsoft Learn — Incidents and alerts in the Microsoft Defender portal"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$An analyst is reviewing an Incident in Defender XDR. They want to take a containment action like isolating a device, stopping a process, or disabling a user account directly from the incident page. Which capability provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Microsoft Defender for Endpoint plan 2 (P2) adds which capability over plan 1 (P1)?$ms102r$, $ms102r$[{"id":"a","text":"Endpoint Detection and Response (EDR), advanced hunting, threat experts, and automated investigation"},{"id":"b","text":"Anti-malware only"},{"id":"c","text":"Conditional Access enforcement"},{"id":"d","text":"Microsoft 365 admin center read-only view"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$MDE P2 includes EDR, advanced hunting, threat experts (now Defender Experts), and AIR — beyond the prevention focus of P1. CA and admin-center access are separate functions.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/advanced-hunting-overview","label":"Microsoft Learn — Advanced hunting in Microsoft Defender XDR"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/automated-investigations","label":"Microsoft Learn — Automated investigation and response in Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Microsoft Defender for Endpoint plan 2 (P2) adds which capability over plan 1 (P1)?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft Defender Antivirus capability protects user folders (Documents, Pictures) from unauthorized modification — a key defense against ransomware encryption?$ms102r$, $ms102r$[{"id":"a","text":"Controlled folder access"},{"id":"b","text":"EDR in block mode"},{"id":"c","text":"ASR rule: Block credential stealing from the Local Security Authority subsystem"},{"id":"d","text":"Tamper protection"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Controlled folder access protects designated folders from changes by unauthorized apps — the textbook ransomware defense. The others address different attack surfaces.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/attack-surface-reduction","label":"Microsoft Learn — Attack surface reduction rules overview"},{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft Defender Antivirus capability protects user folders (Documents, Pictures) from unauthorized modification — a key defense against ransomware encryption?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Defender for Office 365 Safe Links.$ms102r$, $ms102r$[{"id":"a","text":"Safe Links rewrites URLs in messages so they pass through Microsoft scanning at click-time."},{"id":"b","text":"Safe Links also protects URLs inside Microsoft Teams chats and Office apps when configured."},{"id":"c","text":"Safe Links runs only at the time of message delivery."},{"id":"d","text":"A Safe Links policy can be scoped to specific recipients/domains."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$Safe Links rewrites and time-of-click-protects URLs across Outlook, Teams, and Office, and can be scoped by recipient. It does NOT only run at delivery — its value is real-time scanning at click time.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-links-about","label":"Microsoft Learn — Safe Links in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Defender for Office 365 Safe Links.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your CISO wants every email containing executable attachments to be detonated before delivery, even at the cost of slight delivery delays. Which Safe Attachments action best implements this requirement?$ms102r$, $ms102r$[{"id":"a","text":"Block (do not deliver until scan complete)"},{"id":"b","text":"Off"},{"id":"c","text":"Monitor (deliver and log)"},{"id":"d","text":"Replace (deliver placeholder)"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Block holds the message until detonation finishes — strongest protection at the cost of delay. Off/Monitor/Replace either skip scanning or deliver placeholders.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-attachments-about","label":"Microsoft Learn — Safe Attachments in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your CISO wants every email containing executable attachments to be detonated before delivery, even at the cost of slight delivery delays. Which Safe Attachments action best implements this requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A SOC analyst wants to perform a real-time interactive remote shell on a compromised device. Which Defender for Endpoint capability supports this?$ms102r$, $ms102r$[{"id":"a","text":"Live response"},{"id":"b","text":"Vulnerability Management"},{"id":"c","text":"Attack simulation training"},{"id":"d","text":"Conditional Access"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Live response provides an interactive shell on the device, allowing analysts to gather evidence and remediate. The others address different scopes.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A SOC analyst wants to perform a real-time interactive remote shell on a compromised device. Which Defender for Endpoint capability supports this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to alert on a non-standard scenario: a high number of multifactor-prompt failures followed by a successful sign-in from the same user. Which Defender XDR capability should you use to author the detection?$ms102r$, $ms102r$[{"id":"a","text":"Custom detection rule on advanced hunting"},{"id":"b","text":"A retention policy"},{"id":"c","text":"A DLP rule"},{"id":"d","text":"A communication compliance review"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$A custom detection rule built on a KQL hunting query alerts on the exact pattern. Retention, DLP, and communication compliance are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/advanced-hunting-overview","label":"Microsoft Learn — Advanced hunting in Microsoft Defender XDR"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to alert on a non-standard scenario: a high number of multifactor-prompt failures followed by a successful sign-in from the same user. Which Defender XDR capability should you use to author the detection?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Defender for Endpoint device is in compliance with all policies, but the SOC wants to test a new attack-surface-reduction rule before forcing it. Which mode should they choose?$ms102r$, $ms102r$[{"id":"a","text":"Audit mode — events are logged without blocking, so analysts can validate impact before switching to Block"},{"id":"b","text":"Off mode"},{"id":"c","text":"Warn mode"},{"id":"d","text":"Block immediately"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Audit mode logs but does not block — perfect for safe rollout. Off mode does nothing. Warn prompts the user. Blocking immediately risks breaking apps.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/attack-surface-reduction","label":"Microsoft Learn — Attack surface reduction rules overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Defender for Endpoint device is in compliance with all policies, but the SOC wants to test a new attack-surface-reduction rule before forcing it. Which mode should they choose?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to publish a DMARC TXT record for fabrikam.com with strict alignment and 100% policy enforcement. Which DMARC tag value enforces "reject"?$ms102r$, $ms102r$[{"id":"a","text":"p=reject"},{"id":"b","text":"p=none"},{"id":"c","text":"p=quarantine"},{"id":"d","text":"p=monitor"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$DMARC tag p=reject instructs recipients to reject unauthenticated messages. p=none monitors; p=quarantine sends to junk; p=monitor is not a valid DMARC value.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/email-authentication-dmarc-configure","label":"Microsoft Learn — Use DMARC to validate email"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to publish a DMARC TXT record for fabrikam.com with strict alignment and 100% policy enforcement. Which DMARC tag value enforces "reject"?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A Microsoft Defender for Identity alert mentions "Suspicious LDAP enumeration". This signal originates from which sensor placement?$ms102r$, $ms102r$[{"id":"a","text":"The Defender for Identity sensor installed on domain controllers"},{"id":"b","text":"The Microsoft Defender for Endpoint agent on a workstation"},{"id":"c","text":"The Defender for Office 365 connector"},{"id":"d","text":"The Microsoft 365 admin center service health"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$MDI sensors on DCs see LDAP traffic and emit on-prem identity-attack alerts. MDE focuses on endpoints, MDO on mail, and admin-center health on incidents.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-for-identity/what-is","label":"Microsoft Learn — What is Microsoft Defender for Identity?"},{"url":"https://learn.microsoft.com/en-us/defender-for-identity/deploy/capacity-planning","label":"Microsoft Learn — Plan capacity for Microsoft Defender for Identity"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A Microsoft Defender for Identity alert mentions "Suspicious LDAP enumeration". This signal originates from which sensor placement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Defender for Cloud Apps feature lets you analyze user consent grants to third-party OAuth apps and revoke risky ones from the Defender portal?$ms102r$, $ms102r$[{"id":"a","text":"OAuth app governance (App governance / App management)"},{"id":"b","text":"Cloud Discovery upload"},{"id":"c","text":"Conditional Access App Control"},{"id":"d","text":"File policies"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$OAuth app governance reviews consented OAuth apps and supports revocation. Cloud Discovery is for shadow IT logs. CA App Control is session control. File policies inspect file content.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/control-cloud-apps-with-policies","label":"Microsoft Learn — Control cloud apps with policies"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Defender for Cloud Apps feature lets you analyze user consent grants to third-party OAuth apps and revoke risky ones from the Defender portal?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to ensure that anti-spam policies in EOP send spoofed messages to the recipient's Junk Email folder (not quarantine) so users can recover them faster. Which setting handles this?$ms102r$, $ms102r$[{"id":"a","text":"Anti-spam policy action for \"Spoofed sender\" or \"Phishing\" set to \"Move message to Junk Email folder\""},{"id":"b","text":"A retention policy"},{"id":"c","text":"A Conditional Access named location"},{"id":"d","text":"A DLP rule"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Anti-spam policy actions can move to junk, quarantine, redirect, or NDR. The others do not control mail action.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/anti-spam-protection-about","label":"Microsoft Learn — Anti-spam protection in EOP"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/eop-about","label":"Microsoft Learn — Exchange Online Protection overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to ensure that anti-spam policies in EOP send spoofed messages to the recipient's Junk Email folder (not quarantine) so users can recover them faster. Which setting handles this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want endpoint protection to automatically block malware as soon as it's detected (not just alert). Which Defender for Endpoint feature provides this for processes that EDR identifies as malicious?$ms102r$, $ms102r$[{"id":"a","text":"EDR in block mode"},{"id":"b","text":"Audit mode"},{"id":"c","text":"Passive AV mode"},{"id":"d","text":"Tamper protection"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$EDR in block mode lets EDR remediate detected post-breach threats. Audit mode logs only. Passive AV is for third-party AV. Tamper protection prevents AV settings from being altered.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-endpoint/microsoft-defender-endpoint","label":"Microsoft Learn — Microsoft Defender for Endpoint"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want endpoint protection to automatically block malware as soon as it's detected (not just alert). Which Defender for Endpoint feature provides this for processes that EDR identifies as malicious?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user reports legitimate mail keeps being quarantined as phishing. Which is the recommended Microsoft path to investigate and adjust?$ms102r$, $ms102r$[{"id":"a","text":"Use Submissions in the Defender portal to submit the message and adjust anti-phish/SCL settings as needed"},{"id":"b","text":"Delete the user account"},{"id":"c","text":"Open a Microsoft Entra incident"},{"id":"d","text":"Apply a Conditional Access named location"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Submissions in the Defender portal report false positives and feed Microsoft's detection. Deleting accounts, Entra incidents, and CA named locations are unrelated remedies.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/quarantine-about","label":"Microsoft Learn — Quarantined email messages in EOP and Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user reports legitimate mail keeps being quarantined as phishing. Which is the recommended Microsoft path to investigate and adjust?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Defender for Cloud Apps Conditional Access App Control session policies.$ms102r$, $ms102r$[{"id":"a","text":"They route user sessions through Defender for Cloud Apps reverse proxy for inspection."},{"id":"b","text":"They can block file download from unmanaged devices while still allowing read in the browser."},{"id":"c","text":"They can apply sensitivity labels to documents downloaded."},{"id":"d","text":"They replace the need for Microsoft Entra Conditional Access policies."}]$ms102r$::jsonb, $ms102r$["a","b","c"]$ms102r$::jsonb, $ms102r$CA App Control routes sessions for inline inspection, supports block-download and label-on-download policies. It complements — not replaces — Conditional Access (which must invoke it).$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/what-is-defender-for-cloud-apps","label":"Microsoft Learn — What is Microsoft Defender for Cloud Apps?"},{"url":"https://learn.microsoft.com/en-us/defender-cloud-apps/control-cloud-apps-with-policies","label":"Microsoft Learn — Control cloud apps with policies"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Defender for Cloud Apps Conditional Access App Control session policies.$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Where can administrators view security recommendations to improve their organization's posture and track the impact of each recommendation on the overall score?$ms102r$, $ms102r$[{"id":"a","text":"Microsoft Secure Score in the Defender portal"},{"id":"b","text":"Microsoft Entra ID Protection only"},{"id":"c","text":"Microsoft Purview Audit"},{"id":"d","text":"Microsoft 365 admin center > Setup"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft Secure Score is the centralized recommendations and posture-tracking dashboard. ID Protection is risk-focused. Purview Audit is for activities. M365 admin center Setup is initial setup tasks.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-secure-score","label":"Microsoft Learn — Microsoft Secure Score"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Where can administrators view security recommendations to improve their organization's posture and track the impact of each recommendation on the overall score?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A security baseline assessment in Defender Vulnerability Management compares device configurations against which standards?$ms102r$, $ms102r$[{"id":"a","text":"Industry benchmarks (e.g. CIS) and Microsoft security baselines (e.g. Microsoft 365 Apps and Windows)"},{"id":"b","text":"Only PCI-DSS scoring"},{"id":"c","text":"Only Microsoft Entra group memberships"},{"id":"d","text":"Only the Microsoft 365 admin center user list"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Security baselines assessment compares device settings against CIS and Microsoft baselines. PCI-DSS is one of many possible frameworks but is not the dedicated assessment source. Entra group lists are not device-config baselines.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-vulnerability-management/defender-vulnerability-management","label":"Microsoft Learn — Microsoft Defender Vulnerability Management"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A security baseline assessment in Defender Vulnerability Management compares device configurations against which standards?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft 365 capability lets you simulate a phishing campaign that uses a "credential harvest" payload and tracks user click rates and credential submissions?$ms102r$, $ms102r$[{"id":"a","text":"Attack simulation training in Defender for Office 365"},{"id":"b","text":"Microsoft Entra ID Protection sign-in risk"},{"id":"c","text":"Microsoft Defender for Cloud Apps"},{"id":"d","text":"Microsoft Purview DLP simulation mode"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Attack simulation training supports multiple payloads including credential harvest and reports user behavior. The other options either don't simulate phishing or don't track click rates.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/attack-simulation-training-get-started","label":"Microsoft Learn — Get started using Attack simulation training"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft 365 capability lets you simulate a phishing campaign that uses a "credential harvest" payload and tracks user click rates and credential submissions?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which set of products are unified in Microsoft Defender XDR for cross-product incident correlation?$ms102r$, $ms102r$[{"id":"a","text":"Defender for Endpoint, Defender for Office 365, Defender for Identity, Defender for Cloud Apps"},{"id":"b","text":"Microsoft 365 Apps, Power BI, Power Automate, OneDrive"},{"id":"c","text":"Microsoft Entra Connect, AD FS, Microsoft Authenticator, FIDO2 keys"},{"id":"d","text":"SharePoint, Teams, Forms, Lists"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Microsoft Defender XDR (formerly Microsoft 365 Defender) correlates incidents across Defender for Endpoint, Office 365, Identity, and Cloud Apps. The other groupings are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender","label":"Microsoft Learn — Microsoft Defender XDR overview"},{"url":"https://learn.microsoft.com/en-us/defender-xdr/microsoft-365-defender-portal","label":"Microsoft Learn — The Microsoft Defender portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which set of products are unified in Microsoft Defender XDR for cross-product incident correlation?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A user receives a phishing email that bypassed your filters. ZAP retroactively detects the message as malicious. What is the BEST outcome ZAP performs?$ms102r$, $ms102r$[{"id":"a","text":"It moves the message from the user's mailbox to quarantine after delivery (retroactive purge)"},{"id":"b","text":"It revokes the user's license"},{"id":"c","text":"It deletes the user account"},{"id":"d","text":"It rotates the tenant DKIM keys"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Zero-hour Auto Purge moves messages to quarantine after delivery as new signal arrives. The other actions are not part of ZAP.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/mdo-about","label":"Microsoft Learn — Microsoft Defender for Office 365"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/safe-links-about","label":"Microsoft Learn — Safe Links in Microsoft Defender for Office 365"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A user receives a phishing email that bypassed your filters. ZAP retroactively detects the message as malicious. What is the BEST outcome ZAP performs?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to detect and warn users (without blocking) when they share a document containing U.S. SSNs in OneDrive externally. Which Purview policy action should you use?$ms102r$, $ms102r$[{"id":"a","text":"A DLP policy with the \"Notify users only\" action (policy tip) and no block"},{"id":"b","text":"A retention policy delete-only"},{"id":"c","text":"Information barriers segment"},{"id":"d","text":"Compliance Manager improvement action"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$DLP policies offer "Notify users only" tips and "Restrict access" actions. Retention is lifecycle; information barriers prevent communication; Compliance Manager scores frameworks.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp","label":"Microsoft Learn — Data Loss Prevention overview"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-create-deploy-policy","label":"Microsoft Learn — Create and deploy a data loss prevention policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to detect and warn users (without blocking) when they share a document containing U.S. SSNs in OneDrive externally. Which Purview policy action should you use?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage security and threats by using Microsoft Defender XDR$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to ensure that anti-malware on Exchange Online inspects messages for both file content and known patterns. Which EOP policy must be enabled?$ms102r$, $ms102r$[{"id":"a","text":"Anti-malware policy (default policy or custom)"},{"id":"b","text":"A retention policy"},{"id":"c","text":"A Conditional Access named location"},{"id":"d","text":"A DLP allow list"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$EOP anti-malware policy inspects messages for malware patterns and known dangerous file types. Retention, named locations, and DLP allow-lists do not perform malware detection.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/defender-office-365/anti-malware-protection-about","label":"Microsoft Learn — Anti-malware protection in EOP"},{"url":"https://learn.microsoft.com/en-us/defender-office-365/eop-about","label":"Microsoft Learn — Exchange Online Protection overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to ensure that anti-malware on Exchange Online inspects messages for both file content and known patterns. Which EOP policy must be enabled?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Your sensitivity-label taxonomy has "Public, General, Confidential, Highly Confidential". You want Confidential to allow Co-Authoring by employees and Highly Confidential to block external sharing. Which capability covers BOTH controls?$ms102r$, $ms102r$[{"id":"a","text":"Encryption permissions in the sensitivity label, plus integration with DLP for sharing prevention on Highly Confidential"},{"id":"b","text":"A communication compliance policy"},{"id":"c","text":"An information barrier policy"},{"id":"d","text":"A retention policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Sensitivity-label encryption controls intra-label permissions; DLP rules referencing the label can prevent external sharing of labeled content. Other features address different concerns.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitivity-labels","label":"Microsoft Learn — Learn about sensitivity labels"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-create-deploy-policy","label":"Microsoft Learn — Create and deploy a data loss prevention policy"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Your sensitivity-label taxonomy has "Public, General, Confidential, Highly Confidential". You want Confidential to allow Co-Authoring by employees and Highly Confidential to block external sharing. Which capability covers BOTH controls?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Where do you author a custom sensitive information type that matches a 9-digit account number with a confidence score and proximity to keywords like "Account No"?$ms102r$, $ms102r$[{"id":"a","text":"Data classification > Classifiers > Sensitive info types > Create info type in the Microsoft Purview portal"},{"id":"b","text":"Defender XDR > Hunting"},{"id":"c","text":"Conditional Access policies"},{"id":"d","text":"Compliance Manager assessments"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Custom SITs are authored in Data classification > Classifiers > Sensitive info types, supporting regex, keywords, confidence, and proximity. The other tools are unrelated.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/sensitive-information-type-learn-about","label":"Microsoft Learn — Sensitive information types in Microsoft Purview"},{"url":"https://learn.microsoft.com/en-us/purview/data-classification-overview","label":"Microsoft Learn — Data classification in the Microsoft Purview portal"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Where do you author a custom sensitive information type that matches a 9-digit account number with a confidence score and proximity to keywords like "Account No"?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$A regulator demands that you retain emails for finance employees for 7 years and then automatically delete them. Which Purview construct best meets this requirement?$ms102r$, $ms102r$[{"id":"a","text":"A retention policy targeting Exchange mailboxes scoped to the Finance group, with retain-and-delete after 7 years"},{"id":"b","text":"A DLP policy blocking deletion"},{"id":"c","text":"A sensitivity label with encryption"},{"id":"d","text":"A communication compliance policy"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Retention policies support retain-then-delete with a defined period and scope. DLP cannot enforce retention; sensitivity labels protect, not retain; communication compliance reviews messages.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/create-retention-policies","label":"Microsoft Learn — Create and configure retention policies"},{"url":"https://learn.microsoft.com/en-us/purview/retention","label":"Microsoft Learn — Learn about retention policies and retention labels"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$A regulator demands that you retain emails for finance employees for 7 years and then automatically delete them. Which Purview construct best meets this requirement?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$MULTI$ms102r$::"QType", $ms102r$Select ALL true statements about Microsoft Purview eDiscovery (Premium).$ms102r$, $ms102r$[{"id":"a","text":"It supports custodian management and legal-hold notifications."},{"id":"b","text":"It can collect content from M365 and place it in a review set for analytics, redaction, and export."},{"id":"c","text":"It can encrypt mailboxes automatically."},{"id":"d","text":"It supports analytics like near-duplicate detection and email-thread analysis."}]$ms102r$::jsonb, $ms102r$["a","b","d"]$ms102r$::jsonb, $ms102r$eDiscovery (Premium) supports custodians, legal-hold notifications, collections into review sets, redaction, export, and analytics (near-dup, thread). It does not perform mailbox encryption — that's a sensitivity-label concern.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/ediscovery-overview","label":"Microsoft Learn — Overview of eDiscovery (Premium)"},{"url":"https://learn.microsoft.com/en-us/purview/ediscovery","label":"Microsoft Learn — Microsoft Purview eDiscovery solutions"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Select ALL true statements about Microsoft Purview eDiscovery (Premium).$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 3, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want communication-compliance reviewers to see Teams messages flagged for harassment, but with the sender's name pseudonymized to reduce bias. Which feature provides this?$ms102r$, $ms102r$[{"id":"a","text":"Pseudonymization in communication compliance reviewer settings"},{"id":"b","text":"Anonymous IP detection in ID Protection"},{"id":"c","text":"Privileged Access Management in Microsoft Purview"},{"id":"d","text":"Information Barriers"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Communication compliance supports pseudonymizing the sender for fairness in reviews. ID Protection deals with sign-in risk. PAM controls privileged tasks. Information Barriers prevent communication, not anonymized review.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/communication-compliance","label":"Microsoft Learn — Learn about communication compliance"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want communication-compliance reviewers to see Teams messages flagged for harassment, but with the sender's name pseudonymized to reduce bias. Which feature provides this?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$You want to detect when a departing employee downloads many files containing trade secrets and prevent further sharing. Which Purview features should you combine?$ms102r$, $ms102r$[{"id":"a","text":"Insider risk management to surface the risky behavior, plus DLP to prevent sharing of the labeled content"},{"id":"b","text":"Communication compliance only"},{"id":"c","text":"Information Barriers only"},{"id":"d","text":"eDiscovery (Standard) only"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Combining insider risk management (behavior detection) with DLP (action prevention) addresses both the signal and the control. Other options miss one of those halves.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/insider-risk-management","label":"Microsoft Learn — Learn about insider risk management"},{"url":"https://learn.microsoft.com/en-us/purview/dlp-learn-about-dlp","label":"Microsoft Learn — Data Loss Prevention overview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$You want to detect when a departing employee downloads many files containing trade secrets and prevent further sharing. Which Purview features should you combine?$ms102r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ms102r$Manage compliance by using Microsoft Purview$ms102r$, 2, $ms102r$SINGLE$ms102r$::"QType", $ms102r$Which Microsoft Purview solution requires Privileged Access Management to be configured so that a Global Administrator must request approval to perform a sensitive Exchange task?$ms102r$, $ms102r$[{"id":"a","text":"Privileged access management (PAM) in Microsoft Purview"},{"id":"b","text":"Microsoft Entra Privileged Identity Management for Microsoft 365"},{"id":"c","text":"Information Barriers"},{"id":"d","text":"Compliance Manager"}]$ms102r$::jsonb, $ms102r$["a"]$ms102r$::jsonb, $ms102r$Purview PAM enforces just-in-time approval for sensitive Exchange tasks at the task level. Entra PIM addresses role activation. Information Barriers and Compliance Manager have different roles.$ms102r$, $ms102r$[{"url":"https://learn.microsoft.com/en-us/purview/privileged-access-management","label":"Microsoft Learn — Privileged access management in Microsoft Purview"}]$ms102r$::jsonb, $ms102r$PUBLISHED$ms102r$::"QStatus", $ms102r$manual:ms102-seed$ms102r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $ms102r$microsoft-ms-102-p3$ms102r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ms102r$Which Microsoft Purview solution requires Privileged Access Management to be configured so that a Global Administrator must request approval to perform a sensitive Exchange task?$ms102r$);
